import React, { useState } from 'react';
import { useGameStore } from '../store/gameStore';

export default function AuthPage() {
  const [mode, setMode] = useState<'login' | 'register'>('login');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const { login, register, loginAsGuest, addToast } = useGameStore();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    if (mode === 'login') {
      const ok = login(username, password);
      if (!ok) setError('Invalid username or password');
      else addToast('success', `Welcome back, ${username}!`);
    } else {
      if (username.length < 3) { setError('Username must be at least 3 characters'); return; }
      const ok = register(username, password);
      if (!ok) setError('Username already taken');
      else addToast('success', `Account created! Starting balance: ₹10,000`);
    }
  };

  return (
    <div className="min-h-screen bg-gray-950 flex flex-col items-center justify-center px-4">
      {/* Logo */}
      <div className="mb-8 text-center">
        <div className="flex items-center justify-center gap-2 mb-2">
          <span className="text-4xl font-black text-white">66</span>
          <span className="text-2xl font-bold text-red-500">Lottery</span>
        </div>
        <p className="text-gray-400 text-sm">WinGo Color Prediction Game</p>
      </div>

      {/* Card */}
      <div className="w-full max-w-sm bg-gray-900 rounded-2xl p-6 border border-gray-800 shadow-2xl">
        {/* Tabs */}
        <div className="flex rounded-xl overflow-hidden mb-6 bg-gray-800">
          <button
            onClick={() => { setMode('login'); setError(''); }}
            className={`flex-1 py-3 text-sm font-semibold transition-all ${
              mode === 'login' ? 'bg-red-600 text-white' : 'text-gray-400 hover:text-white'
            }`}
          >
            Login
          </button>
          <button
            onClick={() => { setMode('register'); setError(''); }}
            className={`flex-1 py-3 text-sm font-semibold transition-all ${
              mode === 'register' ? 'bg-red-600 text-white' : 'text-gray-400 hover:text-white'
            }`}
          >
            Register
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-xs text-gray-400 mb-1 font-medium">Username</label>
            <input
              type="text"
              value={username}
              onChange={e => setUsername(e.target.value)}
              placeholder="Enter username"
              required
              className="w-full bg-gray-800 border border-gray-700 rounded-lg px-4 py-3 text-white text-sm focus:outline-none focus:border-red-500 placeholder-gray-600"
            />
          </div>
          <div>
            <label className="block text-xs text-gray-400 mb-1 font-medium">Password</label>
            <input
              type="password"
              value={password}
              onChange={e => setPassword(e.target.value)}
              placeholder="Enter password"
              className="w-full bg-gray-800 border border-gray-700 rounded-lg px-4 py-3 text-white text-sm focus:outline-none focus:border-red-500 placeholder-gray-600"
            />
          </div>

          {error && (
            <div className="text-red-400 text-xs bg-red-950 border border-red-800 rounded-lg px-3 py-2">
              {error}
            </div>
          )}

          <button
            type="submit"
            className="w-full bg-red-600 hover:bg-red-500 text-white font-bold py-3 rounded-xl transition-colors text-sm"
          >
            {mode === 'login' ? 'Login' : 'Create Account'}
          </button>
        </form>

        {/* Demo credentials hint */}
        <div className="mt-4 p-3 bg-gray-800 rounded-lg text-xs text-gray-400">
          <p className="font-semibold text-gray-300 mb-1">Demo Credentials:</p>
          <p>Username: <span className="text-yellow-400">Demo</span> / Password: <span className="text-yellow-400">demo123</span></p>
        </div>

        {/* Guest Login */}
        <div className="mt-4 text-center">
          <span className="text-gray-500 text-xs">or</span>
          <button
            onClick={() => { loginAsGuest(); addToast('info', 'Logged in as Guest with ₹10,000'); }}
            className="block w-full mt-2 py-3 border border-gray-700 rounded-xl text-gray-300 text-sm hover:bg-gray-800 transition-colors font-medium"
          >
            🎮 Play as Guest
          </button>
        </div>
      </div>
    </div>
  );
}

