      </div>
    );
  }

  if (!user) {
    return (
      <>
        <AuthPage />
        <ToastContainer />
      </>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100">
      <div className="max-w-lg mx-auto min-h-screen bg-gray-100 relative shadow-2xl">
        <Header />
        <SessionTabs />
        <div className="pb-6">
          <CountdownPanel />
          <BettingPanel />
          <CurrentBets />
          <GameHistory />
        </div>
        <ResultAnnouncement />
        <ToastContainer />
      </div>
    </div>
  );
}

