import { create } from 'zustand';
import { supabase } from '../lib/supabase';
import { useGameStore } from './gameStore';

interface AuthStore {
  user: any | null;
  profile: any | null;
  loading: boolean;
  setUser: (user: any) => void;
  setProfile: (profile: any) => void;
  refreshProfile: () => Promise<void>;
  signOut: () => Promise<void>;
  initialize: () => Promise<void>;
}

export const useAuthStore = create<AuthStore>((set, get) => ({
  user: null,
  profile: null,
  loading: true,

  setUser: (user) => set({ user }),
  setProfile: (profile) => set({ profile }),

  refreshProfile: async () => {
    const { user } = get();
    if (!user) return;

    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', user.id)
        .single();

      if (!error && data) {
        set({ profile: data });
        useGameStore.getState().syncUser({
          id: data.id,
          username: data.username,
          balance: data.balance
        });
      }
    } catch (err) {
      console.error('Error refreshing profile:', err);
    }
  },

  signOut: async () => {
    try {
      await supabase.auth.signOut();
    } catch (error) {
      console.error('Error signing out:', error);
    } finally {
      set({ user: null, profile: null });
      useGameStore.getState().syncUser(null);
    }
  },

  initialize: async () => {
    console.log('Auth: Starting initialization...');

    const timer = setTimeout(() => {
      if (get().loading) {
        console.warn('Auth: Initialization timed out after 5s');
        set({ loading: false });
      }
    }, 5000);

    try {
      console.log('Auth: Fetching session...');
      const { data: { session }, error: sessionError } = await supabase.auth.getSession();

      if (sessionError) {
        console.error('Auth: Session fetch error:', sessionError);
      }

      if (session?.user) {
        console.log('Auth: Session found for user:', session.user.id);
        set({ user: session.user });

        console.log('Auth: Fetching profile from database...');
        const { data: profile, error: profileError } = await supabase
          .from('profiles')
          .select('*')
          .eq('id', session.user.id)
          .single();

        if (profileError) {
          console.error('Auth: Profile fetch error (Check if SQL setup was run):', profileError);
        }

        if (profile) {
          console.log('Auth: Profile loaded successfully');
          set({ profile });
          useGameStore.getState().syncUser({
            id: profile.id,
            username: profile.username,
            balance: profile.balance
          });
        }
      } else {
        console.log('Auth: No active session found');
      }
    } catch (err) {
      console.error('Auth: Unexpected initialization error:', err);
    } finally {
      clearTimeout(timer);
      set({ loading: false });
      console.log('Auth: Initialization process finished');
    }
  }
}));

// Listen for auth changes
supabase.auth.onAuthStateChange(async (event, session) => {
  console.log('Auth state change:', event);
  const store = useAuthStore.getState();
  if (session?.user) {
    store.setUser(session.user);
    await store.refreshProfile();
  } else {
    store.setUser(null);
    store.setProfile(null);
    useGameStore.getState().syncUser(null);
  }
  useAuthStore.setState({ loading: false });
});

