import { useState } from 'react';
import { useAuthStore } from '../store/authStore';
import WalletModal from './WalletModal';

export default function Header() {
  const { profile, signOut } = useAuthStore();
  const [showWallet, setShowWallet] = useState(false);

  const initials = profile?.username?.substring(0, 2).toUpperCase() || 'GU';

  return (
    <>
      <header className="bg-red-600 text-white p-4 sticky top-0 z-50 shadow-md">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-white/20 flex items-center justify-center font-bold text-sm border border-white/30">
              {initials}
            </div>
            <div>
              <p className="text-xs text-red-100 opacity-80">Welcome,</p>
              <p className="text-sm font-bold leading-none">{profile?.username || 'Guest'}</p>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={() => setShowWallet(true)}
              className="bg-black/20 hover:bg-black/30 transition-colors px-3 py-1.5 rounded-full flex items-center gap-2 border border-white/10"
            >
              <span className="text-yellow-400 font-bold text-sm">₹{profile?.balance?.toFixed(2) || '0.00'}</span>
              <svg className="w-4 h-4 text-white/70" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 4v16m8-8H4" />
              </svg>
            </button>

            <button 
              onClick={() => signOut()}
              className="p-2 hover:bg-white/10 rounded-full transition-colors"
              title="Logout"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
              </svg>
            </button>
          </div>
        </div>
      </header>

      {showWallet && <WalletModal onClose={() => setShowWallet(false)} />}
    </>
  );
}

