  const { user } = get();
  if (!user) return;

  try {
    const { data, error } = await supabase
      .from('profiles')
      .select('*')
      .eq('id', user.id)
      .single();

    if (data) {
      set({ profile: data });
      useGameStore.getState().syncUser({
        id: data.id,
        username: data.username,
        balance: data.balance
      });
    } else if (error && error.code === 'PGRST116') {
      // PGRST116 means 0 rows returned (Profile is missing).
      // Let's create it directly in the DB to fix accounts created before the trigger.
      console.warn('Auth: Profile missing in DB. Attempting to create it...');
      const newProfile = {
        id: user.id,
        username: user.user_metadata?.username || user.email?.split('@')[0] || 'Player',
        balance: 10000.00
      };

      const { data: insertedProfile, error: insertError } = await supabase
        .from('profiles')
        .insert([newProfile])
        .select()
        .single();

      if (insertedProfile) {
        console.warn('Auth: Profile successfully created and recovered!');
        set({ profile: insertedProfile });
        useGameStore.getState().syncUser(insertedProfile);
      } else {
        console.error('Auth: Failed to create missing profile. Logging out to prevent broken state.', insertError);
        await get().signOut();
      }
    } else {
      console.error('Auth: Error fetching profile:', error);
    }
  } catch (err) {
    console.error('Error refreshing profile:', err);
  }
},

signOut: async () => {
  try {
    await supabase.auth.signOut();
    // Explicitly clear any remaining auth-related items from storage
    for (const key in localStorage) {
      if (key.includes('supabase.auth')) localStorage.removeItem(key);
    }
  } catch (error) {
    console.error('Error signing out:', error);
