import { create } from 'zustand';
import { supabase } from '../lib/supabase';
import { useGameStore } from './gameStore';

interface AuthStore {
  user: any | null;
  profile: any | null;
  loading: boolean;
  setUser: (user: any) => void;
  setProfile: (profile: any) => void;
  refreshProfile: () => Promise<void>;
  signOut: () => Promise<void>;
  initialize: () => Promise<void>;
}

export const useAuthStore = create<AuthStore>((set, get) => ({
  user: null,
  profile: null,
  loading: true,

  setUser: (user) => set({ user }),
  setProfile: (profile) => set({ profile }),

  refreshProfile: async () => {
    const { user } = get();
    if (!user) return;

    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', user.id)
        .single();

      if (data) {
        set({ profile: data });
        useGameStore.getState().syncUser({
          id: data.id,
          username: data.username,
          balance: data.balance
        });
      } else if (error && error.code === 'PGRST116') {
        // PGRST116 means 0 rows returned (Profile is missing).
        // Let's create it directly in the DB to fix accounts created before the trigger.
        console.warn('Auth: Profile missing in DB. Attempting to create it...');
        const newProfile = {
          id: user.id,
          username: user.user_metadata?.username || user.email?.split('@')[0] || 'Player',
          balance: 10000.00
        };

        const { data: insertedProfile, error: insertError } = await supabase
          .from('profiles')
          .insert([newProfile])
          .select()
          .single();

        if (insertedProfile) {
          console.warn('Auth: Profile successfully created and recovered!');
          set({ profile: insertedProfile });
          useGameStore.getState().syncUser(insertedProfile);
        } else {
          console.error('Auth: Failed to create missing profile. Logging out to prevent broken state.', insertError);
          await get().signOut();
        }
      } else {
        console.error('Auth: Error fetching profile:', error);
        const fallbackProfile = {
          id: user.id,
          username: user.user_metadata?.username || user.email?.split('@')[0] || 'Player',
          balance: 10000.00
        };
        set({ profile: fallbackProfile });
        useGameStore.getState().syncUser(fallbackProfile);
      }
    } catch (err) {
      console.error('Auth: Network or unexpected error refreshing profile:', err);
      // Failsafe: if the network completely drops or adblocker blocks the request,
      // give them a temporary local profile so the app doesn't break
      const offlineProfile = {
        id: user.id,
        username: user.user_metadata?.username || user.email?.split('@')[0] || 'Player',
        balance: 10000.00
      };
      set({ profile: offlineProfile });
      useGameStore.getState().syncUser(offlineProfile);
    }
  },

  signOut: async () => {
    try {
      await supabase.auth.signOut();
      // Explicitly clear any remaining auth-related items from storage
      for (const key in localStorage) {
        if (key.includes('supabase.auth')) localStorage.removeItem(key);
      }
    } catch (error) {
      console.error('Error signing out:', error);
    } finally {
      set({ user: null, profile: null });
      useGameStore.getState().syncUser(null);
    }
  },

  initialize: () => {
    console.warn('Auth: Store initialized, waiting for Supabase to emit session...');

    // Failsafe timer just in case Supabase never fires an event
    setTimeout(() => {
      if (get().loading) {
        console.warn('Auth: Failsafe triggered. Forcing loading to false.');
        set({ loading: false });
      }
    }, 4000);
  }
}));

// Listen for auth changes. In Supabase v2, this fires immediately on load with INITIAL_SESSION
supabase.auth.onAuthStateChange(async (event, session) => {
  console.warn('Auth state change:', event, session?.user?.id);
  const store = useAuthStore.getState();

  if (session?.user) {
    if (session.user.is_anonymous) {
      console.warn('Auth: Anonymous user detected, signing out...');
      await supabase.auth.signOut();
      store.setUser(null);
      store.setProfile(null);
      useGameStore.getState().syncUser(null);
      useAuthStore.setState({ loading: false });
      return;
    }

    store.setUser(session.user);
    await store.refreshProfile();
  } else {
    store.setUser(null);
    store.setProfile(null);
    useGameStore.getState().syncUser(null);
  }
  useAuthStore.setState({ loading: false });
});

