import { create } from 'zustand';
import { supabase } from '../lib/supabase';
import { useGameStore } from './gameStore';

interface AuthStore {
  user: any | null;
  profile: any | null;
  loading: boolean;
  refreshProfile: () => Promise<void>;
  signOut: () => Promise<void>;
  initialize: () => void;
}

export const useAuthStore = create<AuthStore>((set, get) => ({
  user: null,
  profile: null,
  loading: true,

  refreshProfile: async () => {
    const { user } = get();
    if (!user) return;

    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', user.id)
        .single();

      if (data) {
        set({ profile: data });
        useGameStore.getState().syncUser({
          id: data.id,
          username: data.username,
          balance: data.balance
        });
      } else if (error && error.code === 'PGRST116') {
        console.warn('Auth: Profile missing in DB. Attempting to create it...');
        const newProfile = {
          id: user.id,
          username: user.user_metadata?.username || user.email?.split('@')[0] || 'Player',
          balance: 10000.00
        };

        const { data: insertedProfile, error: insertError } = await supabase
          .from('profiles')
          .insert([newProfile])
          .select()
          .single();

        if (insertedProfile) {
          set({ profile: insertedProfile });
          useGameStore.getState().syncUser(insertedProfile);
        } else {
          console.error('Auth: Failed to create missing profile.', insertError);
          await get().signOut();
        }
      } else {
        console.error('Auth: Error fetching profile:', error);
        // Fallback to metadata to prevent UI hang
        const fallback = {
          id: user.id,
          username: user.user_metadata?.username || user.email?.split('@')[0] || 'Player',
          balance: 10000.00
        };
        set({ profile: fallback });
        useGameStore.getState().syncUser(fallback);
      }
    } catch (err) {
      console.error('Auth: Exception in refreshProfile:', err);
    }
  },

  signOut: async () => {
    try {
      await supabase.auth.signOut();

      // Safely iterate only over actual storage keys
      Object.keys(localStorage).forEach(key => {
        if (key.includes('supabase.auth')) {
          localStorage.removeItem(key);
        }
      });
    } catch (error) {
      console.error('Error signing out:', error);
    } finally {
      set({ user: null, profile: null });
      useGameStore.getState().syncUser(null);
    }
  },

  initialize: () => {
    console.warn('Auth: Store initialized, waiting for session...');
    setTimeout(() => {
      if (get().loading) {
        set({ loading: false });
      }
    }, 4000);
  }
}));

// Robust Auth Listener
supabase.auth.onAuthStateChange(async (event, session) => {
  console.warn('Auth state change:', event, session?.user?.id);

  if (session?.user && !session.user.is_anonymous) {
    // Update state directly using Zustand's setState
    useAuthStore.setState({ user: session.user });

    // Fetch the profile now that the user is set
    await useAuthStore.getState().refreshProfile();
  } else {
    // Clear everything if logged out or anonymous
    if (session?.user?.is_anonymous) {
      await supabase.auth.signOut();
    }
    useAuthStore.setState({ user: null, profile: null });
    useGameStore.getState().syncUser(null);
  }

  // Resolve the loading state only after the profile fetch finishes (or fails)
  useAuthStore.setState({ loading: false });
});

