import { create } from 'zustand';
import { supabase } from '../lib/supabase';
import { useGameStore } from './gameStore';

interface AuthStore {
  user: any | null;
  profile: any | null;
  loading: boolean;
  initialized: boolean;
  refreshProfile: (userId: string) => Promise<void>;
  signOut: () => Promise<void>;
  initialize: () => void;
}

export const useAuthStore = create<AuthStore>((set, get) => ({
  user: null,
  profile: null,
  loading: true,
  initialized: false, // Prevents double-execution in React Strict Mode

  refreshProfile: async (userId: string) => {
    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .single();

      if (error) throw error;

      if (data) {
        set({ profile: data });
        useGameStore.getState().syncUser({
          id: data.id,
          username: data.username,
          balance: data.balance
        });
      }
    } catch (err) {
      console.error('Production Auth Error - Profile Fetch Failed:', err);
      // Strict production approach: if it fails, set profile to null
      set({ profile: null }); 
    }
  },

  initialize: () => {
    // Stop React Strict Mode from running this twice
    if (get().initialized) return;
    set({ initialized: true, loading: true });

    // 1. Fetch initial session safely
    supabase.auth.getSession().then(async ({ data: { session }, error }) => {
      if (error) {
        console.error('Session retrieval failed:', error);
        set({ user: null, profile: null, loading: false });
        return;
      }

      if (session?.user && !session.user.is_anonymous) {
        set({ user: session.user });
        await get().refreshProfile(session.user.id);
      } else {
        set({ user: null, profile: null });
      }

      // Guaranteed to run after profile fetch completes or fails
      set({ loading: false });
    });

    // 2. Listen for auth changes (login/logout)
    supabase.auth.onAuthStateChange(async (event, session) => {
      if (event === 'INITIAL_SESSION') return; 

      if (session?.user && !session.user.is_anonymous) {
        set({ user: session.user, loading: true });
        await get().refreshProfile(session.user.id);
        set({ loading: false });
      } else {
        set({ user: null, profile: null, loading: false });
        useGameStore.getState().syncUser(null);
      }
    });
  },

  signOut: async () => {
    try {
      set({ loading: true });
      await supabase.auth.signOut();
      // Safely iterate only over actual storage keys
      Object.keys(localStorage).forEach(key => {
        if (key.includes('supabase.auth')) {
          localStorage.removeItem(key);
        }
      });
    } catch (err) {
      console.error('Sign out error:', err);
    } finally {
      set({ user: null, profile: null, loading: false });
      useGameStore.getState().syncUser(null);
    }
  }
}));

