import { useEffect, useState } from 'react';
import { useGameStore, startGameTick } from './store/gameStore';
import { useAuthStore } from './store/authStore';
import AuthPage from './components/AuthPage';
import Header from './components/Header';
import SessionTabs from './components/SessionTabs';
import CountdownPanel from './components/CountdownPanel';
import BettingPanel from './components/BettingPanel';
import CurrentBets from './components/CurrentBets';
import GameHistory from './components/GameHistory';
import ToastContainer from './components/ToastContainer';
import ResultAnnouncement from './components/ResultAnnouncement';
import BottomNav, { TabType } from './components/BottomNav';
import WalletModal from './components/WalletModal';

// ── Placeholder Components for New Tabs ──

const AllGamesView = () => (
  <div className="p-4 space-y-4">
    <h2 className="text-xl font-bold text-gray-800">Available Games</h2>
    <div className="grid grid-cols-2 gap-4">
      <div className="bg-red-500 h-32 rounded-2xl flex items-center justify-center text-white font-bold text-lg shadow-lg">WinGo</div>
      <div className="bg-gray-200 h-32 rounded-2xl flex items-center justify-center text-gray-400 font-bold border-2 border-dashed border-gray-300">Coming Soon</div>
      <div className="bg-gray-200 h-32 rounded-2xl flex items-center justify-center text-gray-400 font-bold border-2 border-dashed border-gray-300">Coming Soon</div>
      <div className="bg-gray-200 h-32 rounded-2xl flex items-center justify-center text-gray-400 font-bold border-2 border-dashed border-gray-300">Coming Soon</div>
    </div>
  </div>
);

const ActivityView = () => (
  <div className="p-4 space-y-4">
    <h2 className="text-xl font-bold text-gray-800">Activity & Rewards</h2>
    <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
      <div className="flex items-center gap-4 mb-4">
        <div className="w-12 h-12 bg-yellow-100 rounded-full flex items-center justify-center text-yellow-600">
          <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-1.203 1.538-1.902.71l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.699.828-2.202.211-1.902-.71l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" /></svg>
        </div>
        <div>
          <h3 className="font-bold">Daily Check-in</h3>
          <p className="text-gray-500 text-xs">Get up to ₹100 every day</p>
        </div>
      </div>
      <button className="w-full bg-red-600 text-white font-bold py-3 rounded-xl shadow-md">Check-in Now</button>
    </div>
  </div>
);

const PromotionView = () => (
  <div className="p-4 space-y-4">
    <h2 className="text-xl font-bold text-gray-800">Refer & Earn</h2>
    <div className="bg-gradient-to-br from-red-500 to-red-700 p-6 rounded-3xl text-white shadow-xl">
      <h3 className="text-2xl font-black mb-2">Invite Friends</h3>
      <p className="text-red-100 text-sm mb-6">Earn up to 10% commission on your friend's bets!</p>
      <div className="bg-white/20 p-4 rounded-xl backdrop-blur-md border border-white/30 flex items-center justify-between">
        <span className="font-mono font-bold tracking-widest text-lg">X7A9B2K</span>
        <button className="bg-white text-red-600 px-4 py-2 rounded-lg font-bold text-sm shadow-sm">COPY</button>
      </div>
    </div>
  </div>
);

const AccountView = ({ profile, onLogout, onWallet }: { profile: any, onLogout: () => void, onWallet: () => void }) => (
  <div className="p-4 space-y-6 pb-24">
    <div className="flex items-center gap-4 bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
      <div className="w-20 h-20 bg-red-600 rounded-full flex items-center justify-center text-white text-3xl font-black border-4 border-red-50 shadow-inner">
        {profile?.username?.substring(0, 1).toUpperCase()}
      </div>
      <div>
        <h2 className="text-2xl font-black text-gray-800 leading-tight">{profile?.username}</h2>
        <p className="text-gray-400 text-sm font-medium">User ID: {profile?.id?.substring(0, 8)}</p>
        <div className="mt-2 inline-flex items-center gap-1.5 px-3 py-1 bg-green-50 text-green-600 rounded-full text-[10px] font-bold uppercase tracking-wider">
          <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span> Verified Account
        </div>
      </div>
    </div>

    <div className="grid grid-cols-2 gap-4">
      <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
        <p className="text-gray-400 text-xs font-bold uppercase mb-1">Balance</p>
        <p className="text-2xl font-black text-red-600">₹{profile?.balance?.toFixed(2)}</p>
      </div>
      <button onClick={onWallet} className="bg-red-600 p-4 rounded-2xl shadow-lg flex flex-col justify-center items-center text-white gap-1 active:scale-95 transition-all">
        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
        <span className="font-bold text-sm">Deposit</span>
      </button>
    </div>

    <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">
      {[
        { label: 'Betting Records', icon: '📋' },
        { label: 'Transaction History', icon: '💰' },
        { label: 'Gift Code', icon: '🎁' },
        { label: 'Settings', icon: '⚙️' },
      ].map((item, idx) => (
        <button key={idx} className="w-full flex items-center justify-between p-5 hover:bg-gray-50 border-b border-gray-50 last:border-0">
          <div className="flex items-center gap-4">
            <span className="text-xl">{item.icon}</span>
            <span className="font-bold text-gray-700">{item.label}</span>
          </div>
          <svg className="w-5 h-5 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" /></svg>
        </button>
      ))}
    </div>

    <button onClick={onLogout} className="w-full bg-gray-200 text-gray-600 font-bold py-4 rounded-2xl hover:bg-gray-300 transition-colors">
      Log Out
    </button>
  </div>
);

// ── Main App Component ──

export default function App() {
  const { user, loading, initialize, profile, signOut } = useAuthStore();
  const [activeTab, setActiveTab] = useState<TabType>('wingo');
  const [showWallet, setShowWallet] = useState(false);

  useEffect(() => {
    // Single consolidated initialization
    initialize();
    startGameTick();
  }, [initialize]);

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-950 flex flex-col items-center justify-center">
        <div className="text-red-600 animate-pulse font-black text-2xl italic tracking-tighter mb-4">
          LOADING...
        </div>
        <div className="text-gray-500 text-xs font-mono max-w-[200px] text-center">
          Initializing secure connection with Supabase
        </div>
      </div>
    );
  }

  if (!user) {
    return (
      <>
        <AuthPage />
        <ToastContainer />
      </>
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'wingo':
        return (
          <div className="pb-24">
            <CountdownPanel />
            <BettingPanel />
            <CurrentBets />
            <GameHistory />
          </div>
        );
      case 'all-games':
        return <AllGamesView />;
      case 'activity':
        return <ActivityView />;
      case 'promotion':
        return <PromotionView />;
      case 'account':
        return <AccountView profile={profile} onLogout={signOut} onWallet={() => setShowWallet(true)} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-gray-100">
      <div className="max-w-lg mx-auto min-h-screen bg-gray-100 relative shadow-2xl overflow-x-hidden">
        <Header />

        {activeTab === 'wingo' && <SessionTabs />}

        <div className="flex-1">
          {renderContent()}
        </div>

        <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} />

        <ResultAnnouncement />
        <ToastContainer />
        {showWallet && <WalletModal onClose={() => setShowWallet(false)} />}
      </div>
    </div>
  );
}

