import { useEffect } from 'react';
import confetti from 'canvas-confetti';
import { useGameStore, GameResult } from '../store/gameStore';

interface ResultOverlayProps {
  won: boolean;
  amount: number;
  result: GameResult;
  onClose: () => void;
}

function ResultOverlay({ won, amount, result, onClose }: ResultOverlayProps) {
  useEffect(() => {
    if (won) {
      // Fire confetti from bottom left and right
      const duration = 3000;
      const end = Date.now() + duration;

      const frame = () => {
        confetti({
          particleCount: 5,
          angle: 60,
          spread: 55,
          origin: { x: 0, y: 0.8 },
          colors: ['#26cc00', '#ff0000', '#ffffff']
        });
        confetti({
          particleCount: 5,
          angle: 120,
          spread: 55,
          origin: { x: 1, y: 0.8 },
          colors: ['#26cc00', '#ff0000', '#ffffff']
        });

        if (Date.now() < end) {
          requestAnimationFrame(frame);
        }
      };
      frame();
    }

    const timer = setTimeout(onClose, 5000);
    return () => clearTimeout(timer);
  }, [won, onClose]);

  const colorLabel =
    result.color === 'red-violet' ? 'Red + Violet' :
    result.color === 'green-violet' ? 'Green + Violet' :
    result.color.charAt(0).toUpperCase() + result.color.slice(1);

  const ballGradient =
    result.color === 'red-violet' ? 'from-red-500 to-violet-600' :
    result.color === 'green-violet' ? 'from-green-500 to-violet-600' :
    result.color === 'green' ? 'from-green-400 to-green-600' :
    result.color === 'red' ? 'from-red-400 to-red-600' :
    'from-violet-400 to-violet-600';

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/75 backdrop-blur-sm"
      onClick={onClose}
    >
      <div
        className="bg-white rounded-[2rem] overflow-hidden shadow-2xl text-center max-w-[320px] w-full mx-4 animate-pop border-4 border-white"
        onClick={e => e.stopPropagation()}
      >
        {/* Header Section */}
        <div className={`py-6 px-4 ${won ? 'bg-green-500' : 'bg-red-500'} text-white`}>
          <div className="text-sm font-bold uppercase tracking-widest opacity-80 mb-1">
            {won ? 'Congratulations' : 'Better Luck Next Time'}
          </div>
          <div className="text-3xl font-black drop-shadow-md">
            {won ? 'YOU WON!' : 'YOU LOST'}
          </div>
        </div>

        <div className="p-6">
          <div className="text-gray-400 text-[10px] font-mono mb-4 uppercase tracking-tighter">
            {result.session_type?.toUpperCase() || 'SESSION'} PERIOD: {result.period}
          </div>

          {/* Big number ball */}
          <div
            className={`w-24 h-24 rounded-full bg-gradient-to-br ${ballGradient} flex items-center justify-center mx-auto mb-4 shadow-xl border-4 border-white ring-4 ring-gray-50`}
          >
            <span className="text-white font-black text-5xl drop-shadow-lg">{result.number}</span>
          </div>

          <div className="flex justify-center gap-2 mb-6">
            <span className="bg-gray-100 text-gray-700 text-xs font-bold px-3 py-1 rounded-full border border-gray-200">
              {colorLabel}
            </span>
            <span className="bg-gray-100 text-gray-700 text-xs font-bold px-3 py-1 rounded-full border border-gray-200">
              {result.big_small}
            </span>
          </div>

          {won && (
            <div className="mb-6 animate-bounce">
              <div className="text-xs text-gray-400 font-bold uppercase mb-1">Winning Amount</div>
              <div className="text-3xl font-black text-green-600">
                + ₹{amount.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
              </div>
            </div>
          )}

          {!won && (
             <div className="mb-6">
              <div className="text-xs text-gray-400 font-bold uppercase mb-1">Try again!</div>
              <div className="text-xl font-bold text-gray-400">
                Zero winnings
              </div>
            </div>
          )}

          <button
            onClick={onClose}
            className={`w-full ${won ? 'bg-green-500 hover:bg-green-600' : 'bg-red-500 hover:bg-red-600'} text-white font-bold py-4 rounded-2xl text-sm transition-all shadow-lg active:scale-95`}
          >
            CLOSE
          </button>
        </div>
      </div>
    </div>
  );
}

