// ─── Pure Game Logic ──────────────────────────────────────────────────────────

export function getColorForNumber(num: number): ColorValue | 'red-violet' | 'green-violet' {
  if (num === 0) return 'red-violet';
  if (num === 5) return 'green-violet';
  if ([1, 3, 7, 9].includes(num)) return 'green';
  return 'red';
}

export function getSizeForNumber(num: number): 'Big' | 'Small' {
  return num >= 5 ? 'Big' : 'Small';
}

export function getMultiplierForBet(type: BetType, value: ColorValue | SizeValue | number): number {
  if (type === 'number') return 9;
  if (type === 'color') {
    if (value === 'violet') return 4.5;
    return 2;
  }
  return 2;
}

export function calculateWin(bet: Bet, resultNumber: number): number {
  const color = getColorForNumber(resultNumber);
  const size = getSizeForNumber(resultNumber);

  if (bet.type === 'number') {
    if (bet.value === resultNumber) return bet.amount * 9;
    return 0;
  }

  if (bet.type === 'color') {
    if (bet.value === 'green') {
      if (color === 'green' || color === 'green-violet') return bet.amount * 2;
    }
    if (bet.value === 'red') {
      if (color === 'red' || color === 'red-violet') return bet.amount * 2;
    }
    if (bet.value === 'violet') {
      if (color === 'red-violet' || color === 'green-violet') return bet.amount * 4.5;
    }
    return 0;
  }

  if (bet.type === 'size') {
    if (bet.value === 'big' && size === 'Big') return bet.amount * 2;
    if (bet.value === 'small' && size === 'Small') return bet.amount * 2;
    return 0;
  }

  return 0;
}

export function computeHouseResult(bets: Bet[]): number {
  let bestNumber = 0;
  let lowestPayout = Infinity;

  for (let num = 0; num <= 9; num++) {
    let totalPayout = 0;
    for (const bet of bets) {
      totalPayout += calculateWin(bet, num);
    }
    if (totalPayout < lowestPayout) {
      lowestPayout = totalPayout;
      bestNumber = num;
    } else if (totalPayout === lowestPayout) {
      if (Math.random() < 0.5) bestNumber = num;
    }
  }

  return bestNumber;
}

export function generatePeriod(sessionType: SessionType, counter: number): string {
  const now = new Date();
  const dateStr = now.toISOString().split('T')[0].replace(/-/g, '');
  const paddedCounter = String(counter).padStart(5, '0');

  const prefixes: Record<SessionType, string> = {
    '30s': '30s', '1min': '01', '3min': '03', '5min': '05', '10min': '10',
  };

  return `${dateStr}${prefixes[sessionType]}${paddedCounter}`;
}

// ─── Zustand Store ────────────────────────────────────────────────────────────

interface ToastMessage {
  id: string;
  type: 'success' | 'error' | 'win' | 'loss' | 'info';
  message: string;
}

interface GameStore {
  user: User | null;
  syncUser: (user: User | null) => void;
  syncUserBalance: (balance: number) => void;

  activeSession: SessionType;
  setActiveSession: (s: SessionType) => void;

  sessions: Record<SessionType, SessionState>;
  counters: Record<SessionType, number>;

  selectedBet: { type: BetType; value: ColorValue | SizeValue | number } | null;
  selectedMultiplier: number;
  setSelectedBet: (bet: { type: BetType; value: ColorValue | SizeValue | number } | null) => void;
  setSelectedMultiplier: (m: number) => void;
  placeBet: (amount: number) => Promise<void>;
  randomBet: () => void;

  historyTab: 'game' | 'chart' | 'my';
  setHistoryTab: (t: 'game' | 'chart' | 'my') => void;

  myBets: Bet[];
  lastRoundResult: {
    session: SessionType;
    won: boolean;
    amount: number;
    result: GameResult;
  } | null;
  clearLastRoundResult: () => void;

  toasts: ToastMessage[];
  addToast: (type: ToastMessage['type'], message: string) => void;
  removeToast: (id: string) => void;

  tick: () => void;
}

function makeInitialSession(sessionType: SessionType, counter: number): SessionState {
  const { durationSeconds } = SESSION_CONFIGS[sessionType];
  const nowInSeconds = Math.floor(Date.now() / 1000);
  const timeLeft = durationSeconds - (nowInSeconds % durationSeconds);

  return {
    sessionType,
    period: generatePeriod(sessionType, counter),
    timeLeft,
    isAcceptingBets: timeLeft > 5,
    history: [],
    currentBets: [],
    lastResult: null,
  };
}

const INITIAL_COUNTERS: Record<SessionType, number> = {
  '30s': 100, '1min': 100, '3min': 100, '5min': 100, '10min': 100,
};
function generateSeedHistory(sessionType: SessionType, startCounter: number): GameResult[] {
  const results: GameResult[] = [];
  const now = Date.now();
  for (let i = 1; i <= 20; i++) {
    const counter = startCounter - i;
    const num = Math.floor(Math.random() * 10) as NumberValue;
    results.push({
      period: generatePeriod(sessionType, counter),
      number: num,
      color: getColorForNumber(num),
      big_small: getSizeForNumber(num),
      session_type: sessionType,
      timestamp: now - i * SESSION_CONFIGS[sessionType].durationSeconds * 1000,
    });
  }
  return results;
}

export const useGameStore = create<GameStore>((set, get) => ({
  user: null,
  syncUser: (user) => set({ user }),
  syncUserBalance: (balance) => {
    set(s => ({ user: s.user ? { ...s.user, balance } : null }));
  },

  activeSession: '1min',
  setActiveSession: (s) => set({ activeSession: s }),

  sessions: {
    '30s':   { ...makeInitialSession('30s',   INITIAL_COUNTERS['30s']),   history: generateSeedHistory('30s',   INITIAL_COUNTERS['30s'])   },
    '1min':  { ...makeInitialSession('1min',  INITIAL_COUNTERS['1min']),  history: generateSeedHistory('1min',  INITIAL_COUNTERS['1min'])  },
    '3min':  { ...makeInitialSession('3min',  INITIAL_COUNTERS['3min']),  history: generateSeedHistory('3min',  INITIAL_COUNTERS['3min'])  },
    '5min':  { ...makeInitialSession('5min',  INITIAL_COUNTERS['5min']),  history: generateSeedHistory('5min',  INITIAL_COUNTERS['5min'])  },
    '10min': { ...makeInitialSession('10min', INITIAL_COUNTERS['10min']), history: generateSeedHistory('10min', INITIAL_COUNTERS['10min']) },
  },

  counters: INITIAL_COUNTERS,

  selectedBet: null,
  selectedMultiplier: 1,
  isPlacingBet: false,
  setSelectedBet: (bet) => set({ selectedBet: bet }),
  setSelectedMultiplier: (m) => set({ selectedMultiplier: m }),

  async placeBet(amount) {
    const { user, selectedBet, activeSession, sessions, selectedMultiplier, isPlacingBet } = get();
    if (!user) { get().addToast('error', 'Please login first'); return; }
    if (!selectedBet) { get().addToast('error', 'Please select a bet option'); return; }
    if (isPlacingBet) { get().addToast('info', 'Processing bet, please wait...'); return; }

    const session = sessions[activeSession];
    if (!session.isAcceptingBets) {
      get().addToast('error', 'Betting is closed for this round');
      return;
    }

    const totalAmount = amount * selectedMultiplier;
    if (user.balance < totalAmount) {
      get().addToast('error', 'Insufficient balance');
      return;
    }

    set({ isPlacingBet: true });

    try {
      const betData = {
        user_id: user.id,
        type: selectedBet.type,
        value: String(selectedBet.value),
        amount: totalAmount,
        session_type: activeSession,
        period: session.period,
      };

      // Insert bet to Supabase
      const { data: insertedBet, error } = await supabase
        .from('bets')
        .insert([betData])
        .select()
        .single();

      if (error) {
        get().addToast('error', 'Failed to place bet: ' + error.message);
        return;
      }

      // Deduct balance via Secure RPC Function
      const { data: edgeData, error: edgeError } = await supabase.rpc('update_user_balance', {
        p_user_id: user.id,
        p_amount: -totalAmount,
        p_reason: 'bet',
        p_details: { period: session.period, session: activeSession, bet_id: insertedBet.id }
      });

      if (edgeError || edgeData?.error) {
        // If balance deduction fails, rollback the bet insertion
        await supabase.from('bets').delete().eq('id', insertedBet.id);
        get().addToast('error', edgeData?.error || edgeError?.message || 'Failed to deduct balance for bet');
        return;
      }

      const newBalance = edgeData.balance;

      set(s => ({
        user: { ...s.user!, balance: newBalance },
        sessions: {
          ...s.sessions,
          [activeSession]: {
            ...s.sessions[activeSession],
            currentBets: [...s.sessions[activeSession].currentBets, { ...insertedBet, value: selectedBet.value }],
          },
        },
      }));

      get().addToast('success', `Bet placed: ₹${totalAmount.toLocaleString()} on ${String(selectedBet.value).toUpperCase()}`);
    } finally {
      set({ isPlacingBet: false });
    }
  },

  randomBet() {
    const types: Array<{ type: BetType; value: ColorValue | SizeValue | number }> = [
      { type: 'color', value: 'green' }, { type: 'color', value: 'red' }, { type: 'color', value: 'violet' },
      { type: 'size', value: 'big' }, { type: 'size', value: 'small' },
      ...Array.from({ length: 10 }, (_, i) => ({ type: 'number' as BetType, value: i })),
    ];
    set({ selectedBet: types[Math.floor(Math.random() * types.length)] });
  },

  historyTab: 'game',
  setHistoryTab: (t) => set({ historyTab: t }),

  myBets: [],
  lastRoundResult: null,
  clearLastRoundResult: () => set({ lastRoundResult: null }),

  toasts: [],
  addToast(type, message) {
    const id = `toast_${Date.now()}_${Math.random()}`;
    set(s => ({ toasts: [...s.toasts, { id, type, message }] }));
    setTimeout(() => get().removeToast(id), 4000);
  },
  removeToast(id) {
    set(s => ({ toasts: s.toasts.filter(t => t.id !== id) }));
  },

  tick() {
    set(state => {
      const newSessions = { ...state.sessions };
      const newCounters = { ...state.counters };
      let newUser = state.user ? { ...state.user } : null;
      const newMyBets = [...state.myBets];
      let newLastRoundResult = state.lastRoundResult;
      const pendingToasts: Array<{ type: ToastMessage['type']; message: string }> = [];

      for (const st of SESSION_ORDER) {
        const session = { ...newSessions[st] };
        session.timeLeft -= 1;

        if (session.timeLeft <= 5) session.isAcceptingBets = false;

        if (session.timeLeft <= 0) {
          const resultNumber = computeHouseResult(session.currentBets);
          const resultColor = getColorForNumber(resultNumber);
          const resultBigSmall = getSizeForNumber(resultNumber);

          const result: GameResult = {
            period: session.period,
            number: resultNumber,
            color: resultColor,
            big_small: resultBigSmall,
            session_type: st,
            timestamp: Date.now(),
          };

          // Persistence: Save Result to Supabase
          supabase.from('games').insert([{
            period: result.period,
            number: result.number,
            color: result.color,
            big_small: result.big_small,
            session_type: result.session_type,
          }]).then();
          // Handle winning and balance update
          let totalWin = 0;
          let hadBetInSession = session.currentBets.length > 0;

          for (const bet of session.currentBets) {
            const payout = calculateWin(bet, resultNumber);
            if (payout > 0 && newUser) {
              newUser.balance += payout;
              totalWin += payout;
            }
            newMyBets.push({
              ...bet,
              result: resultNumber,
              won: payout > 0,
              payout,
            });
          }

          if (totalWin > 0 && newUser) {
            // Process payout via Secure Edge Function
            supabase.functions.invoke('update-balance', {
              body: {
                user_id: newUser.id,
                amount: totalWin,
                reason: 'win',
                payment_details: { period: session.period, session: st }
              }
            }).then(({ error }) => {
              if (error) console.error('Failed to process win payout:', error);
            });
          }

          if (hadBetInSession) {
            newLastRoundResult = { session: st, won: totalWin > 0, amount: totalWin, result: result };
            if (totalWin > 0) {
              pendingToasts.push({ type: 'win', message: `🎉 You won ₹${totalWin.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}! Result: ${resultNumber}` });
            } else {
              pendingToasts.push({ type: 'loss', message: `Result: ${resultNumber}. Better luck next time!` });
            }
          }

          newCounters[st] = newCounters[st] + 1;
          const { durationSeconds } = SESSION_CONFIGS[st];

          newSessions[st] = {
            ...session,
            period: generatePeriod(st, newCounters[st]),
            timeLeft: durationSeconds,
            isAcceptingBets: true,
            currentBets: [],
            lastResult: result,
            history: [result, ...session.history].slice(0, 50),
          };
        } else {
          newSessions[st] = session;
        }
      }

      setTimeout(() => {
        for (const t of pendingToasts) get().addToast(t.type, t.message);
      }, 0);

      return {
        sessions: newSessions,
        counters: newCounters,
        user: newUser,
        myBets: newMyBets,
        lastRoundResult: newLastRoundResult,
      };
    });
  },
}));

let tickInterval: ReturnType<typeof setInterval> | null = null;

export function startGameTick() {
  if (tickInterval) return;
  tickInterval = setInterval(() => {
    useGameStore.getState().tick();
  }, 1000);
}
}

