import { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { useAuthStore } from '../store/authStore';
import { useGameStore } from '../store/gameStore';

export default function WalletModal({ onClose }: { onClose: () => void }) {
  const { profile, refreshProfile } = useAuthStore();
  const { addToast } = useGameStore();
  const [tab, setTab] = useState<'deposit' | 'withdraw' | 'history'>('deposit');
  const [amount, setAmount] = useState(100);
  const [loading, setLoading] = useState(false);
  const [transactions, setTransactions] = useState<any[]>([]);
  const [paymentMethod, setPaymentMethod] = useState('upi');

  useEffect(() => {
    if (tab === 'history') fetchHistory();
  }, [tab]);

  const fetchHistory = async () => {
    const { data } = await supabase
      .from('transactions')
      .select('*')
      .order('created_at', { ascending: false })
      .limit(20);
    if (data) setTransactions(data);
  };

  const handleTransaction = async (type: 'deposit' | 'withdrawal') => {
    if (!profile?.id) return;

    if (type === 'withdrawal' && amount > (profile?.balance || 0)) {
      addToast('error', 'Insufficient balance');
      return;
    }

    if (type === 'withdrawal' && amount < 200) {
      addToast('error', 'Minimum withdrawal is ₹200');
      return;
    }

    setLoading(true);
    try {
      // Call the Edge Function instead of direct DB manipulation
      const { data, error } = await supabase.functions.invoke('update-balance', {
        body: {
          user_id: profile.id,
          amount: type === 'deposit' ? amount : -amount,
          reason: type,
          payment_details: { method: paymentMethod, simulated: true }
        }
      });

      if (error) {
        throw new Error(error.message || 'Transaction failed');
      }

      if (data?.error) {
        throw new Error(data.error);
      }

      addToast('success', type === 'deposit' ? `₹${amount} deposited successfully via ${paymentMethod.toUpperCase()}!` : `Withdrawal of ₹${amount} requested!`);
      await refreshProfile(profile.id);
      onClose();
    } catch (err: any) {
      console.error('Transaction Error:', err);
      addToast('error', err.message || 'An error occurred during the transaction');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
      <div className="bg-gray-900 w-full max-w-md rounded-3xl overflow-hidden border border-gray-800 shadow-2xl flex flex-col max-h-[90vh]">
        {/* Header */}
        <div className="bg-red-600 px-6 py-4 flex items-center justify-between">
          <div>
            <h3 className="text-white font-bold text-lg">My Wallet</h3>
            <p className="text-red-100 text-xs">Balance: ₹{(profile?.balance || 0).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</p>
          </div>
          <button onClick={onClose} className="text-white/80 hover:text-white p-2">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        {/* Tabs */}
        <div className="flex bg-gray-800 p-1 m-4 rounded-xl">
          {(['deposit', 'withdraw', 'history'] as const).map(t => (
            <button
              key={t}
              onClick={() => setTab(t)}
              className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all capitalize ${
                tab === t ? 'bg-gray-700 text-white shadow-sm' : 'text-gray-400 hover:text-gray-300'
              }`}
            >
              {t}
            </button>
          ))}
        </div>

        <div className="px-6 pb-6 flex-1 overflow-y-auto">
          {tab !== 'history' ? (
            <div className="space-y-6">

              {/* Payment Method Selection */}
              <div>
                <label className="text-gray-400 text-xs font-bold uppercase mb-2 block">Payment Method</label>
                <div className="grid grid-cols-3 gap-2">
                  {['upi', 'usdt', 'bank'].map(method => (
                    <button
                      key={method}
                      onClick={() => setPaymentMethod(method)}
                      className={`py-2 rounded-xl text-xs font-bold border transition-colors uppercase ${
                        paymentMethod === method ? 'bg-red-600/20 border-red-500 text-red-500' : 'bg-gray-800 border-gray-700 text-gray-400'
                      }`}
                    >
                      {method}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="text-gray-400 text-xs font-bold uppercase mb-2 block">Enter Amount (min ₹{tab === 'deposit' ? '100' : '200'})</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 font-bold">₹</span>
                  <input
                    type="number"
                    value={amount || ''}
                    onChange={e => setAmount(Number(e.target.value))}
                    className="w-full bg-gray-800 border-2 border-gray-700 rounded-2xl py-4 pl-8 pr-4 text-white font-bold text-xl focus:border-red-500 transition-colors outline-none"
                  />
                </div>
              </div>

              <div className="grid grid-cols-3 gap-2">
                {[100, 500, 1000, 2000, 5000, 10000].map(val => (
                  <button
                    key={val}
                    onClick={() => setAmount(val)}
                    className={`py-3 rounded-xl text-sm font-bold border transition-colors ${
                      amount === val ? 'bg-red-600/20 border-red-500 text-red-500' : 'bg-gray-800 border-gray-700 text-gray-400'
                    }`}
                  >
                    ₹{val}
                  </button>
                ))}
              </div>

              <button
                onClick={() => handleTransaction(tab)}
                disabled={loading || amount < (tab === 'deposit' ? 100 : 200)}
                className="w-full bg-red-600 hover:bg-red-500 disabled:opacity-50 text-white font-black py-4 rounded-2xl shadow-lg transition-all active:scale-95 text-lg flex justify-center items-center gap-2"
              >
                {loading && (
                  <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                )}
                {loading ? 'Processing...' : tab === 'deposit' ? `Deposit ₹${amount.toLocaleString()}` : `Withdraw ₹${amount.toLocaleString()}`}
              </button>

              <p className="text-[10px] text-gray-500 text-center leading-relaxed">
                {tab === 'deposit' 
                  ? "This is a demo deposit. Funds will be added instantly to your wallet via the secure Edge Function."
                  : "Withdrawals are processed securely via Edge Functions. Minimum withdrawal is ₹200."}
              </p>
            </div>
          ) : (
            <div className="space-y-3">
              {transactions.length === 0 && <p className="text-gray-500 text-center py-8">No transactions yet</p>}
              {transactions.map(tx => (
                <div key={tx.id} className="bg-gray-800/50 border border-gray-800 p-3 rounded-xl flex items-center justify-between">
                  <div>
                    <p className="text-white text-sm font-bold capitalize">{tx.type}</p>
                    <p className="text-gray-500 text-[10px]">{new Date(tx.created_at).toLocaleString()}</p>
                  </div>
                  <div className="text-right">
                    <p className={`text-sm font-black ${tx.type === 'deposit' || tx.type === 'win' ? 'text-green-500' : 'text-red-500'}`}>
                      {tx.type === 'deposit' || tx.type === 'win' ? '+' : '-'}₹{Number(tx.amount).toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits:2})}
                    </p>
                    <p className={`text-[10px] ${tx.status === 'completed' ? 'text-gray-500' : 'text-yellow-500'}`}>{tx.status}</p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

