import React, { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { useAuthStore } from '../store/authStore';
import { useGameStore } from '../store/gameStore';
import { 
  LayoutDashboard, Users, Activity, History, CreditCard, Settings, LogOut, CheckCircle, XCircle 
} from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

export default function AdminPanel() {
  const { profile, signOut } = useAuthStore();
  const { addToast } = useGameStore();
  const [activeTab, setActiveTab] = useState('dashboard');

  const [stats, setStats] = useState({
    totalUsers: 0,
    activeRounds: 5,
    totalBetsToday: 0,
    houseProfit: 0,
    totalRevenue: 0,
  });

  const [users, setUsers] = useState<any[]>([]);
  const [transactions, setTransactions] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (!profile?.is_admin) {
      window.location.href = '/';
      return;
    }
    fetchDashboardData();
  }, [profile]);

  const fetchDashboardData = async () => {
    setLoading(true);
    try {
      // Fetch user count
      const { count: userCount } = await supabase.from('profiles').select('*', { count: 'exact', head: true });

      // Fetch transactions for revenue/profit
      const { data: txs } = await supabase.from('transactions').select('*').gte('created_at', new Date(Date.now() - 86400000).toISOString());

      let profit = 0;
      let revenue = 0;

      if (txs) {
        txs.forEach(tx => {
          if (tx.type === 'loss') profit += Number(tx.amount); // User loss is house profit
          if (tx.type === 'win') profit -= Number(tx.amount); // User win is house loss
          if (tx.type === 'deposit') revenue += Number(tx.amount);
        });
      }

      setStats({
        totalUsers: userCount || 0,
        activeRounds: 5, // Hardcoded as we have 5 sessions
        totalBetsToday: txs?.filter(t => t.type === 'bet').length || 0,
        houseProfit: profit,
        totalRevenue: revenue,
      });

      // Load other data based on tab, or just load all for simplicity if small scale
      const { data: userData } = await supabase.from('profiles').select('*').order('created_at', { ascending: false }).limit(50);
      if (userData) setUsers(userData);

      const { data: txData } = await supabase.from('transactions').select('*').order('created_at', { ascending: false }).limit(50);
      if (txData) setTransactions(txData);

    } catch (error) {
      console.error('Error fetching admin data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleProcessWithdrawal = async (txId: string, approve: boolean) => {
    try {
      const { data, error } = await supabase.rpc('admin_process_withdrawal', {
        p_transaction_id: txId,
        p_approve: approve
      });
      if (error) throw error;
      addToast('success', `Withdrawal ${approve ? 'approved' : 'rejected'}`);
      fetchDashboardData(); // Refresh
    } catch (err: any) {
      addToast('error', err.message);
    }
  };

  const handleEditBalance = async (userId: string, currentBalance: number) => {
    const newBal = prompt('Enter new balance:', currentBalance.toString());
    if (!newBal) return;

    try {
      const { error } = await supabase.rpc('admin_edit_balance', {
        p_target_user_id: userId,
        p_new_balance: Number(newBal),
        p_reason: 'Admin Adjustment'
      });
      if (error) throw error;
      addToast('success', 'Balance updated');
      fetchDashboardData();
    } catch (err: any) {
      addToast('error', err.message);
    }
  };

  const handleForceResult = async (sessionType: string) => {
    const num = prompt(`Force result for ${sessionType}\nEnter number (0-9):`);
    if (num === null) return;

    const parsedNum = parseInt(num);
    if (isNaN(parsedNum) || parsedNum < 0 || parsedNum > 9) {
      addToast('error', 'Invalid number');
      return;
    }

    const color = (parsedNum === 0 || parsedNum === 5) ? (parsedNum === 0 ? 'red-violet' : 'green-violet') : ([1,3,7,9].includes(parsedNum) ? 'green' : 'red');
    const bigSmall = parsedNum >= 5 ? 'Big' : 'Small';

    // We need the current period to force it.
    // In a real implementation, you would pass the current period of that session.
    const currentPeriod = useGameStore.getState().sessions[sessionType as any].period;

    try {
      const { error } = await supabase.rpc('admin_force_result', {
        p_session_type: sessionType,
        p_period: currentPeriod,
        p_number: parsedNum,
        p_color: color,
        p_big_small: bigSmall
      });
      if (error) throw error;
      addToast('success', `Result forced to ${parsedNum} for ${sessionType}`);
    } catch (err: any) {
      addToast('error', err.message);
    }
  };

  // Simplified chart data
  const chartData = [
    { name: 'Mon', profit: 4000 },
    { name: 'Tue', profit: 3000 },
    { name: 'Wed', profit: 5000 },
    { name: 'Thu', profit: 2780 },
    { name: 'Fri', profit: 8890 },
    { name: 'Sat', profit: 6390 },
    { name: 'Sun', profit: stats.houseProfit },
  ];

  if (!profile?.is_admin) return null;

  return (
    <div className="min-h-screen bg-gray-50 flex text-gray-900 font-sans">
      {/* Sidebar */}
      <div className="w-64 bg-gray-900 text-white flex flex-col fixed h-full shadow-2xl z-20">
        <div className="p-6 flex items-center gap-3 border-b border-gray-800">
          <div className="bg-red-600 text-white font-black text-xl w-10 h-10 flex items-center justify-center rounded-xl shadow-lg shadow-red-500/20">66</div>
          <span className="font-bold text-xl tracking-tight">Admin Panel</span>
        </div>

        <nav className="flex-1 py-6 px-4 space-y-2">
          {[
            { id: 'dashboard', icon: LayoutDashboard, label: 'Dashboard' },
            { id: 'monitor', icon: Activity, label: 'Live Games Monitor' },
            { id: 'users', icon: Users, label: 'Users Management' },
            { id: 'history', icon: History, label: 'Bets & History' },
            { id: 'transactions', icon: CreditCard, label: 'Transactions' },
            { id: 'settings', icon: Settings, label: 'Platform Settings' },
          ].map((item) => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${
                activeTab === item.id 
                  ? 'bg-red-600 text-white shadow-md shadow-red-600/20' 
                  : 'text-gray-400 hover:bg-gray-800 hover:text-white'
              }`}
            >
              <item.icon className="w-5 h-5" />
              {item.label}
            </button>
          ))}
        </nav>

        <div className="p-6 border-t border-gray-800">
          <div className="flex items-center gap-3 mb-4">
            <div className="w-10 h-10 rounded-full bg-gray-800 border border-gray-700 flex items-center justify-center font-bold">
              {profile.username.charAt(0).toUpperCase()}
            </div>
            <div>
              <p className="text-sm font-bold text-white leading-tight">{profile.username}</p>
              <p className="text-xs text-red-400">Super Admin</p>
            </div>
          </div>
          <button onClick={() => { signOut(); window.location.href = '/'; }} className="w-full flex items-center gap-2 text-sm text-gray-400 hover:text-white transition-colors bg-gray-800/50 hover:bg-gray-800 p-2 rounded-lg">
            <LogOut className="w-4 h-4" />
            Logout
          </button>
        </div>
      </div>

      {/* Main Content */}
      <div className="ml-64 flex-1 flex flex-col min-h-screen">
        <header className="bg-white h-20 border-b border-gray-200 flex items-center justify-between px-8 sticky top-0 z-10">
          <h1 className="text-2xl font-bold text-gray-800 capitalize tracking-tight">{activeTab.replace('-', ' ')}</h1>
          <div className="flex items-center gap-4">
            <span className="bg-green-100 text-green-700 text-xs font-bold px-3 py-1.5 rounded-full flex items-center gap-1.5 border border-green-200">
              <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
              System Online
            </span>
          </div>
        </header>

        <main className="p-8 flex-1 overflow-y-auto">
          {loading ? (
            <div className="flex items-center justify-center h-64 text-gray-400 font-medium">
              <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-red-500" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              Loading Admin Data...
            </div>
          ) : (
            <>
              {/* Dashboard Tab */}
              {activeTab === 'dashboard' && (
                <div className="space-y-6">
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                    {[
                      { label: 'Total Users', value: stats.totalUsers, icon: Users, color: 'text-blue-600', bg: 'bg-blue-100' },
                      { label: 'Total Bets Today', value: stats.totalBetsToday, icon: Activity, color: 'text-orange-600', bg: 'bg-orange-100' },
                      { label: 'House Profit (24h)', value: `₹${stats.houseProfit.toFixed(2)}`, icon: CreditCard, color: 'text-green-600', bg: 'bg-green-100' },
                      { label: 'Total Revenue', value: `₹${stats.totalRevenue.toFixed(2)}`, icon: CreditCard, color: 'text-purple-600', bg: 'bg-purple-100' },
                    ].map((stat, i) => (
                      <div key={i} className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100 flex items-center gap-4">
                        <div className={`w-14 h-14 rounded-xl flex items-center justify-center ${stat.bg} ${stat.color}`}>
                          <stat.icon className="w-7 h-7" />
                        </div>
                        <div>
                          <p className="text-gray-500 text-sm font-medium">{stat.label}</p>
                          <p className="text-2xl font-black text-gray-900">{stat.value}</p>
                        </div>
                      </div>
                    ))}
                  </div>

                  <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6 h-96">
                    <h2 className="text-lg font-bold text-gray-800 mb-6">House Profit (Last 7 Days)</h2>
                    <ResponsiveContainer width="100%" height="100%">
                      <LineChart data={chartData}>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#E5E7EB" />
                        <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#6B7280'}} dy={10} />
                        <YAxis axisLine={false} tickLine={false} tick={{fill: '#6B7280'}} dx={-10} />
                        <Tooltip 
                          contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.1)' }}
                          cursor={{stroke: '#E5E7EB', strokeWidth: 2}}
                        />
                        <Line type="monotone" dataKey="profit" stroke="#DC2626" strokeWidth={4} dot={{r: 4, strokeWidth: 2}} activeDot={{r: 8}} />
                      </LineChart>
                    </ResponsiveContainer>
                  </div>
                </div>
              )}

              {/* Monitor Tab */}
              {activeTab === 'monitor' && (
                <div className="space-y-6">
                  <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                    <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50/50">
                      <h2 className="text-lg font-bold text-gray-800">Live Session Monitor</h2>
                    </div>
                    <div className="p-6 grid grid-cols-1 gap-6">
                      {['30s', '1min', '3min', '5min', '10min'].map(sessionType => (
                        <div key={sessionType} className="border border-gray-200 rounded-xl p-5 flex items-center justify-between bg-white shadow-sm hover:shadow-md transition-shadow">
                          <div className="flex items-center gap-6">
                            <div className="bg-red-50 text-red-600 px-4 py-2 rounded-lg font-bold text-lg min-w-[100px] text-center border border-red-100">
                              {sessionType.toUpperCase()}
                            </div>
                            <div>
                              <p className="text-sm text-gray-500 font-medium">Status: <span className="text-green-500 font-bold">Active</span></p>
                              <p className="text-sm font-bold text-gray-800 mt-1">Bets: 0  |  Pool: ₹0.00</p>
                            </div>
                          </div>
                          <div className="flex items-center gap-3">
                            <button 
                              onClick={() => handleForceResult(sessionType)}
                              className="px-4 py-2 bg-yellow-100 text-yellow-700 font-bold rounded-lg text-sm hover:bg-yellow-200 transition-colors border border-yellow-200"
                            >
                              Force Result
                            </button>
                            <button className="px-4 py-2 bg-gray-100 text-gray-600 font-bold rounded-lg text-sm hover:bg-gray-200 transition-colors border border-gray-200">
                              Pause Session
                            </button>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>
              )}

              {/* Users Tab */}
              {activeTab === 'users' && (
                <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                  <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50/50">
                    <h2 className="text-lg font-bold text-gray-800">All Users ({users.length})</h2>
                    <input 
                      type="text" 
                      placeholder="Search users..." 
                      className="px-4 py-2 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-red-500 w-64"
                    />
                  </div>
                  <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm text-gray-600">
                      <thead className="bg-gray-50 text-gray-500 font-bold uppercase tracking-wider text-[11px] border-b border-gray-200">
                        <tr>
                          <th className="p-4 pl-6">User</th>
                          <th className="p-4">Balance</th>
                          <th className="p-4">Role</th>
                          <th className="p-4">Joined</th>
                          <th className="p-4 text-right pr-6">Actions</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-gray-100">
                        {users.map(u => (
                          <tr key={u.id} className="hover:bg-gray-50/50 transition-colors">
                            <td className="p-4 pl-6">
                              <div className="flex items-center gap-3">
                                <div className="w-8 h-8 rounded-full bg-red-100 text-red-600 flex items-center justify-center font-bold">
                                  {u.username.charAt(0).toUpperCase()}
                                </div>
                                <div>
                                  <p className="font-bold text-gray-900">{u.username}</p>
                                  <p className="text-[10px] text-gray-400 font-mono">{u.id.substring(0, 8)}...</p>
                                </div>
                              </div>
                            </td>
                            <td className="p-4 font-medium text-gray-900">₹{Number(u.balance).toFixed(2)}</td>
                            <td className="p-4">
