      </div>
    </div>
  </div>
);

const AccountView = ({ profile, onLogout, onWallet }: { profile: any, onLogout: () => void, onWallet: () => void }) => (
  <div className="p-4 space-y-6 pb-24">
    <div className="flex items-center gap-4 bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
      <div className="w-20 h-20 bg-red-600 rounded-full flex items-center justify-center text-white text-3xl font-black border-4 border-red-50 shadow-inner">
        {profile?.username?.substring(0, 1).toUpperCase()}
      </div>
      <div>
        <h2 className="text-2xl font-black text-gray-800 leading-tight">{profile?.username}</h2>
        <p className="text-gray-400 text-sm font-medium">User ID: {profile?.id?.substring(0, 8)}</p>
        <div className="mt-2 inline-flex items-center gap-1.5 px-3 py-1 bg-green-50 text-green-600 rounded-full text-[10px] font-bold uppercase tracking-wider">
          <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span> Verified Account
        </div>
      </div>
    </div>

    <div className="grid grid-cols-2 gap-4">
      <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
        <p className="text-gray-400 text-xs font-bold uppercase mb-1">Balance</p>
        <p className="text-2xl font-black text-red-600">₹{(profile?.balance || 0).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</p>
      </div>
      <button onClick={onWallet} className="bg-red-600 p-4 rounded-2xl shadow-lg flex flex-col justify-center items-center text-white gap-1 active:scale-95 transition-all">
        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
        <span className="font-bold text-sm">Deposit</span>
      </button>
    </div>

    <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">
      {[
        { label: 'Betting Records', icon: '📋' },
        { label: 'Transaction History', icon: '💰' },
        { label: 'Gift Code', icon: '🎁' },
        { label: 'Settings', icon: '⚙️' },
      ].map((item, idx) => (
        <button key={idx} className="w-full flex items-center justify-between p-5 hover:bg-gray-50 border-b border-gray-50 last:border-0">
          <div className="flex items-center gap-4">
            <span className="text-xl">{item.icon}</span>
            <span className="font-bold text-gray-700">{item.label}</span>
          </div>
          <svg className="w-5 h-5 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" /></svg>
        </button>
      ))}
    </div>

    <button onClick={onLogout} className="w-full bg-gray-200 text-gray-600 font-bold py-4 rounded-2xl hover:bg-gray-300 transition-colors">
      Log Out
    </button>
  </div>
);

// ── Main App Component ──

export default function App() {
  const { user, loading, initialize, profile, signOut } = useAuthStore();
  const [activeTab, setActiveTab] = useState<TabType>('wingo');
  const [showWallet, setShowWallet] = useState(false);

  useRealtimeBalance();

  useEffect(() => {
    // Single consolidated initialization
    initialize();
    startGameTick();
  }, [initialize]);

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-950 flex flex-col items-center justify-center">
        <div className="text-red-600 animate-pulse font-black text-2xl italic tracking-tighter mb-4">
          LOADING...
        </div>
        <div className="text-gray-500 text-xs font-mono max-w-[200px] text-center">
          Initializing secure connection with Supabase
        </div>
      </div>
    );
  }

  // Handle Admin Route
  const isAdminRoute = typeof window !== 'undefined' && window.location.pathname.startsWith('/admin');

  if (isAdminRoute && user && profile?.is_admin) {
    return (
      <>
        <AdminPanel />
        <ToastContainer />
      </>
    );
  } else if (isAdminRoute && user && !profile?.is_admin) {
    // Non-admin trying to access admin
    window.location.href = '/';
    return null;
  }

  if (!user) {
    return (
      <>
        <AuthPage />
        <ToastContainer />
      </>
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'wingo':
        return (
          <div className="pb-24">
            <CountdownPanel />
            <BettingPanel />
            <CurrentBets />
            <GameHistory />
          </div>
        );
      case 'all-games':
        return <AllGamesView />;
      case 'activity':
        return <ActivityView />;
      case 'promotion':
        return <PromotionView />;
      case 'account':
        return <AccountView profile={profile} onLogout={signOut} onWallet={() => setShowWallet(true)} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-gray-100">
      <div className="max-w-lg mx-auto min-h-screen bg-gray-100 relative shadow-2xl overflow-x-hidden">
        <Header />

        {activeTab === 'wingo' && <SessionTabs />}

        <div className="flex-1">
          {renderContent()}
        </div>

        <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} />

        <ResultAnnouncement />
        <ToastContainer />
        {showWallet && <WalletModal onClose={() => setShowWallet(false)} />}
      </div>
    </div>
  );
}

