            style={{ padding: "10px 20px", background: "red", color: "white", border: "none", cursor: "pointer", marginTop: "10px" }}
          >
            Reload Page
          </button>
        </div>
      );
    }

    return this.props.children;
  }
}

createRoot(document.getElementById("root")!).render(
