import { useState } from 'react';
import { useAuthStore } from '../store/authStore';
import WalletModal from './WalletModal';

export default function Header() {
  const { user, profile, signOut, refreshProfile } = useAuthStore();
  const [showWallet, setShowWallet] = useState(false);
  const [isRefreshing, setIsRefreshing] = useState(false);

  const initials = profile?.username?.substring(0, 2).toUpperCase() || 'GU';

  const handleRefresh = async () => {
    if (!user?.id || isRefreshing) return;
    setIsRefreshing(true);
    await refreshProfile(user.id);
    setTimeout(() => setIsRefreshing(false), 1000); // 1 second cooldown
  };

  return (
    <>
      <header className="bg-red-600 text-white p-4 sticky top-0 z-50 shadow-md">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-white/20 flex items-center justify-center font-bold text-sm border border-white/30">
              {initials}
            </div>
            <div>
              <p className="text-xs text-red-100 opacity-80">Welcome,</p>
              <p className="text-sm font-bold leading-none">{profile?.username || 'Loading...'}</p>
            </div>
          </div>

          <div className="flex items-center gap-1.5">
            <button
              onClick={handleRefresh}
              disabled={isRefreshing}
              className={`p-1.5 hover:bg-white/10 rounded-full transition-colors ${isRefreshing ? 'opacity-50 cursor-not-allowed' : ''}`}
              title="Refresh Balance"
            >
              <svg className={`w-4 h-4 ${isRefreshing ? 'animate-spin text-yellow-300' : 'text-white/80'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
              </svg>
            </button>

            <button 
              onClick={() => setShowWallet(true)}
              className="bg-black/20 hover:bg-black/30 transition-colors px-3 py-1.5 rounded-full flex items-center gap-2 border border-white/10"
            >
              <span className="text-yellow-400 font-bold text-sm">₹{(profile?.balance || 0).toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</span>
              <svg className="w-4 h-4 text-white/70" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 4v16m8-8H4" />
              </svg>
            </button>

            <button 
              onClick={() => signOut()}
              className="p-2 hover:bg-white/10 rounded-full transition-colors"
              title="Logout"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
              </svg>
            </button>
          </div>
        </div>
      </header>

      {showWallet && <WalletModal onClose={() => setShowWallet(false)} />}
    </>
  );
}

import { useGameStore } from '../store/gameStore';

export default function CurrentBets() {
  const { activeSession, sessions } = useGameStore();
  const session = sessions[activeSession];
  const bets = session.currentBets;

  if (bets.length === 0) return null;

  const totalAmount = bets.reduce((sum, b) => sum + b.amount, 0);

  return (
    <div className="mx-3 mt-3">
      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="flex items-center justify-between px-4 py-3 border-b border-gray-100 bg-gray-50">
          <div className="flex items-center gap-2">
            <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse" />
            <span className="text-gray-700 text-sm font-bold">Your Bets This Round</span>
          </div>
          <span className="text-xs text-gray-500 bg-gray-200 rounded-full px-2 py-0.5 font-medium">
            {bets.length} bet{bets.length > 1 ? 's' : ''}
          </span>
        </div>

        <div className="divide-y divide-gray-50">
          {bets.map(bet => (
            <div key={bet.id} className="flex items-center justify-between px-4 py-2.5">
              <div className="flex items-center gap-2">
                {/* Color/type indicator */}
                <div className={`w-3 h-3 rounded-full ${
                  bet.value === 'green' ? 'bg-green-500' :
                  bet.value === 'violet' ? 'bg-violet-500' :
                  bet.value === 'red' ? 'bg-red-500' :
                  bet.value === 'big' ? 'bg-amber-400' :
                  bet.value === 'small' ? 'bg-blue-500' :
                  'bg-gray-400'
                }`} />
                <span className="text-gray-700 text-sm font-semibold capitalize">
                  {bet.type === 'number' ? `Number ${bet.value}` : String(bet.value)}
                </span>
                <span className="text-gray-400 text-xs">×{bet.multiplier}X</span>
              </div>
              <div className="text-right">
                <span className="font-bold text-gray-800 text-sm">₹{bet.amount}</span>
                <span className="text-gray-400 text-xs ml-1">→ up to ₹{(bet.amount * bet.multiplier).toFixed(0)}</span>
              </div>
            </div>
          ))}
        </div>

        <div className="px-4 py-2.5 bg-gray-50 border-t border-gray-100 flex justify-between items-center">
          <span className="text-gray-500 text-xs font-medium">Total at stake</span>
          <span className="font-black text-red-600">₹{totalAmount.toLocaleString()}</span>
        </div>
      </div>
    </div>
  );
}

