import { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { useAuthStore } from '../store/authStore';
import { useGameStore } from '../store/gameStore';
import { QRCodeSVG } from 'qrcode.react';

export default function WalletModal({ onClose }: { onClose: () => void }) {
  const { profile, refreshProfile } = useAuthStore();
  const { addToast } = useGameStore();
  const [tab, setTab] = useState<'deposit' | 'withdraw' | 'history'>('deposit');
  const [amount, setAmount] = useState(100);
  const [loading, setLoading] = useState(false);
  const [transactions, setTransactions] = useState<any[]>([]);
  const [paymentMethod, setPaymentMethod] = useState('upi');

  // New deposit flow state
  const [depositStep, setDepositStep] = useState<'amount' | 'pay'>('amount');
  const [utr, setUtr] = useState('');
  const [upiId, setUpiId] = useState('yourupi@oksbi');

  useEffect(() => {
    if (tab === 'history') fetchHistory();
    if (tab === 'deposit') {
      fetchSettings();
      setDepositStep('amount'); // Reset step when returning to tab
    }
  }, [tab]);

  const fetchHistory = async () => {
    const { data } = await supabase
      .from('transactions')
      .select('*')
      .order('created_at', { ascending: false })
      .limit(20);
    if (data) setTransactions(data);
  };

  const fetchSettings = async () => {
    const { data } = await supabase.from('app_settings').select('upi_id').single();
    if (data?.upi_id) setUpiId(data.upi_id);
  };

  const handleWithdrawal = async () => {
    if (!profile?.id) return;

    if (amount > (profile?.balance || 0)) {
      addToast('error', 'Insufficient balance');
      return;
    }

    if (amount < 200) {
      addToast('error', 'Minimum withdrawal is ₹200');
      return;
    }

    setLoading(true);
    try {
      const { data, error } = await supabase.rpc('update_user_balance', {
        p_user_id: profile.id,
        p_amount: -amount,
        p_reason: 'withdrawal',
        p_details: { method: paymentMethod }
      });

      if (error) throw new Error(error.message);
      if (data?.error) throw new Error(data.error);

      addToast('success', `Withdrawal of ₹${amount} requested!`);
      await refreshProfile(profile.id);
      onClose();
    } catch (err: any) {
      console.error('Transaction Error:', err);
      addToast('error', err.message || 'An error occurred');
    } finally {
      setLoading(false);
    }
  };

  const handleSubmitDeposit = async () => {
    if (!profile?.id) return;
    if (utr.length < 12) {
      addToast('error', 'Please enter a valid 12-digit UTR number');
      return;
    }

    setLoading(true);
    try {
      const { data, error } = await supabase.rpc('submit_deposit_request', {
        p_user_id: profile.id,
        p_amount: amount,
        p_utr: utr
      });

      if (error) throw new Error(error.message);
      if (data?.error) throw new Error(data.error);

      addToast('success', 'Deposit request submitted successfully! Pending approval.');
      setTab('history'); // Move to history to see pending
    } catch (err: any) {
      console.error('Deposit Error:', err);
      addToast('error', err.message || 'Failed to submit deposit');
    } finally {
      setLoading(false);
    }
  };

  // Generate UPI URI for QR code
  const upiUri = `upi://pay?pa=${upiId}&pn=WinGo%20Platform&am=${amount}&cu=INR`;

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
      <div className="bg-gray-900 w-full max-w-md rounded-3xl overflow-hidden border border-gray-800 shadow-2xl flex flex-col max-h-[90vh]">
        {/* Header */}
        <div className="bg-red-600 px-6 py-4 flex items-center justify-between">
          <div>
            <h3 className="text-white font-bold text-lg">My Wallet</h3>
            <p className="text-red-100 text-xs">Balance: ₹{(profile?.balance || 0).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</p>
          </div>
          <button onClick={onClose} className="text-white/80 hover:text-white p-2">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        {/* Tabs */}
        <div className="flex bg-gray-800 p-1 m-4 rounded-xl">
          {(['deposit', 'withdraw', 'history'] as const).map(t => (
            <button
              key={t}
              onClick={() => setTab(t)}
              className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all capitalize ${
                tab === t ? 'bg-gray-700 text-white shadow-sm' : 'text-gray-400 hover:text-gray-300'
              }`}
            >
              {t}
            </button>
          ))}
        </div>

        <div className="px-6 pb-6 flex-1 overflow-y-auto">
          {tab === 'deposit' && depositStep === 'amount' && (
            <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
              {/* Payment Method Selection */}
              <div>
                <label className="text-gray-400 text-xs font-bold uppercase mb-2 block">Payment Method</label>
                <div className="grid grid-cols-3 gap-2">
                  {['upi', 'usdt', 'bank'].map(method => (
                    <button
                      key={method}
                      onClick={() => setPaymentMethod(method)}
                      className={`py-2 rounded-xl text-xs font-bold border transition-colors uppercase ${
                        paymentMethod === method ? 'bg-red-600/20 border-red-500 text-red-500' : 'bg-gray-800 border-gray-700 text-gray-400 opacity-50 cursor-not-allowed'
                      }`}
                      disabled={method !== 'upi'} // Only UPI supported for now
                    >
                      {method}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="text-gray-400 text-xs font-bold uppercase mb-2 block">Enter Amount (min ₹100)</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 font-bold">₹</span>
                  <input
                    type="number"
                    value={amount || ''}
                    onChange={e => setAmount(Number(e.target.value))}
                    className="w-full bg-gray-800 border-2 border-gray-700 rounded-2xl py-4 pl-8 pr-4 text-white font-bold text-xl focus:border-red-500 transition-colors outline-none"
                  />
                </div>
              </div>

              <div className="grid grid-cols-3 gap-2">
                {[100, 500, 1000, 2000, 5000, 10000].map(val => (
                  <button
                    key={val}
                    onClick={() => setAmount(val)}
                    className={`py-3 rounded-xl text-sm font-bold border transition-colors ${
                      amount === val ? 'bg-red-600/20 border-red-500 text-red-500' : 'bg-gray-800 border-gray-700 text-gray-400 hover:bg-gray-700'
                    }`}
                  >
                    ₹{val}
                  </button>
                ))}
              </div>

              <button
                onClick={() => setDepositStep('pay')}
                disabled={amount < 100}
                className="w-full bg-red-600 hover:bg-red-500 disabled:opacity-50 text-white font-black py-4 rounded-2xl shadow-lg transition-all active:scale-95 text-lg flex justify-center items-center gap-2"
              >
                Deposit ₹{amount.toLocaleString()}
              </button>
            </div>
          )}

          {tab === 'deposit' && depositStep === 'pay' && (
            <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
              <button onClick={() => setDepositStep('amount')} className="text-gray-400 text-sm flex items-center gap-1 hover:text-white">
                &larr; Back to amount
              </button>

              <div className="bg-white p-6 rounded-2xl text-center space-y-4 shadow-[0_0_20px_rgba(220,38,38,0.15)]">
                <p className="text-gray-500 text-xs font-bold uppercase tracking-widest">Scan to Pay</p>
                <div className="bg-gray-100 p-4 rounded-xl inline-block mx-auto border-2 border-gray-200">
                  <QRCodeSVG value={upiUri} size={180} level="H" includeMargin={true} />
                </div>
                <div className="space-y-1">
                  <p className="text-gray-800 font-bold text-xl">₹{amount.toLocaleString()}</p>
                  <p className="text-gray-500 text-sm">UPI ID: <span className="font-bold text-gray-900 select-all">{upiId}</span></p>
                </div>
                <p className="text-xs text-red-600 font-medium bg-red-50 py-2 px-3 rounded-lg border border-red-100">
                  Pay exactly this amount using any UPI app (PhonePe, GPay, Paytm).
                </p>
              </div>

              <div className="space-y-2">
                <label className="text-gray-400 text-xs font-bold uppercase mb-2 block text-center">Step 2: Enter UTR / Ref Number</label>
                <input
                  type="text"
                  value={utr}
                  onChange={e => setUtr(e.target.value)}
                  placeholder="Enter 12-digit UTR number here"
                  className="w-full bg-gray-800 border-2 border-gray-700 rounded-xl py-3 px-4 text-white text-center tracking-widest focus:border-green-500 transition-colors outline-none font-mono placeholder:text-gray-600 placeholder:tracking-normal placeholder:font-sans"
                  maxLength={15}
                />
              </div>

              <button
                onClick={handleSubmitDeposit}
                disabled={loading || utr.length < 12}
                className="w-full bg-green-600 hover:bg-green-500 disabled:opacity-50 text-white font-black py-4 rounded-2xl shadow-lg shadow-green-600/20 transition-all active:scale-95 text-lg flex justify-center items-center gap-2"
              >
                {loading && (
                  <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                )}
                {loading ? 'Submitting...' : 'I Have Paid'}
              </button>
            </div>
          )}

          {tab === 'withdraw' && (
            <div className="space-y-6">
              <div>
                <label className="text-gray-400 text-xs font-bold uppercase mb-2 block">Withdrawal Method</label>
                <div className="grid grid-cols-2 gap-2">
                  {['upi', 'bank'].map(method => (
                    <button
                      key={method}
                      onClick={() => setPaymentMethod(method)}
                      className={`py-2 rounded-xl text-xs font-bold border transition-colors uppercase ${
                        paymentMethod === method ? 'bg-red-600/20 border-red-500 text-red-500' : 'bg-gray-800 border-gray-700 text-gray-400'
                      }`}
                    >
                      {method}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="text-gray-400 text-xs font-bold uppercase mb-2 block">Amount to Withdraw (min ₹200)</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 font-bold">₹</span>
                  <input
                    type="number"
                    value={amount || ''}
                    onChange={e => setAmount(Number(e.target.value))}
                    className="w-full bg-gray-800 border-2 border-gray-700 rounded-2xl py-4 pl-8 pr-4 text-white font-bold text-xl focus:border-red-500 transition-colors outline-none"
                  />
                </div>
              </div>

              <button
                onClick={handleWithdrawal}
                disabled={loading || amount < 200}
                className="w-full bg-red-600 hover:bg-red-500 disabled:opacity-50 text-white font-black py-4 rounded-2xl shadow-lg transition-all active:scale-95 text-lg flex justify-center items-center gap-2"
              >
                {loading && (
                  <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                )}
                {loading ? 'Processing...' : `Withdraw ₹${amount.toLocaleString()}`}
              </button>

              <p className="text-[10px] text-gray-500 text-center leading-relaxed">
                Withdrawals are processed securely via our system. Minimum withdrawal is ₹200.
              </p>
            </div>
          )}

          {tab === 'history' && (
            <div className="space-y-3">
              {transactions.length === 0 && <p className="text-gray-500 text-center py-8">No transactions yet</p>}
              {transactions.map(tx => (
                <div key={tx.id} className="bg-gray-800/50 border border-gray-800 p-4 rounded-2xl flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center ${
                      tx.type === 'deposit' ? 'bg-green-500/20 text-green-500' :
                      tx.type === 'withdrawal' ? 'bg-red-500/20 text-red-500' :
                      tx.type === 'win' ? 'bg-yellow-500/20 text-yellow-500' :
                      'bg-gray-500/20 text-gray-400'
                    }`}>
                      {tx.type === 'deposit' ? '↓' : tx.type === 'withdrawal' ? '↑' : tx.type === 'win' ? '★' : '−'}
                    </div>
                    <div>
                      <p className="text-white text-sm font-bold capitalize">{tx.type}</p>
                      <p className="text-gray-500 text-[10px] uppercase font-bold tracking-widest">{new Date(tx.created_at).toLocaleString()}</p>
                      {tx.utr && <p className="text-gray-600 text-[9px] font-mono mt-0.5">UTR: {tx.utr}</p>}
                    </div>
                  </div>
                  <div className="text-right">
                    <p className={`text-base font-black ${tx.type === 'deposit' || tx.type === 'win' ? 'text-green-500' : 'text-white'}`}>
                      {tx.type === 'deposit' || tx.type === 'win' ? '+' : '-'}₹{Number(tx.amount).toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits:2})}
                    </p>
                    <p className={`text-[10px] font-bold uppercase tracking-wider ${tx.status === 'completed' ? 'text-green-600' : tx.status === 'pending' ? 'text-yellow-500 animate-pulse' : 'text-red-500'}`}>
                      {tx.status}
                    </p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

