    try {
      const { data, error } = await supabase.rpc('admin_process_withdrawal', {
        p_transaction_id: txId,
        p_approve: approve
      });
      if (error) throw error;
      addToast('success', `Withdrawal ${approve ? 'approved' : 'rejected'}`);
      fetchDashboardData();
    } catch (err: any) {
      addToast('error', err.message);
    }
  };

  const handleEditBalance = async (userId: string, currentBalance: number) => {
    const newBal = prompt('Enter new balance:', currentBalance.toString());
    if (!newBal) return;

    try {
      const { error } = await supabase.rpc('admin_edit_balance', {
        p_target_user_id: userId,
        p_new_balance: Number(newBal),
        p_reason: 'Admin Adjustment'
      });
      if (error) throw error;
      addToast('success', 'Balance updated');
      fetchDashboardData();
    } catch (err: any) {
      addToast('error', err.message);
    }
  };

  const handleForceResult = async (sessionType: string) => {
    const num = prompt(`Force result for ${sessionType}\nEnter number (0-9):`);
    if (num === null) return;

    const parsedNum = parseInt(num);
    if (isNaN(parsedNum) || parsedNum < 0 || parsedNum > 9) {
      addToast('error', 'Invalid number');
      return;
    }

    const color = (parsedNum === 0 || parsedNum === 5) ? (parsedNum === 0 ? 'red-violet' : 'green-violet') : ([1,3,7,9].includes(parsedNum) ? 'green' : 'red');

    // Manual choice for Big/Small
    const bsChoice = prompt(`Calculated Size: ${parsedNum >= 5 ? 'Big' : 'Small'}\nEnter 'B' for Big or 'S' for Small (Leave empty to use calculated):`);
    let bigSmall = parsedNum >= 5 ? 'Big' : 'Small';

    if (bsChoice?.toUpperCase() === 'B') bigSmall = 'Big';
    if (bsChoice?.toUpperCase() === 'S') bigSmall = 'Small';

    const currentPeriod = useGameStore.getState().sessions[sessionType as any].period;

    try {
      const { error } = await supabase.rpc('admin_force_result', {
        p_session_type: sessionType,
        p_period: currentPeriod,
        p_number: parsedNum,
        p_color: color,
        p_big_small: bigSmall
      });
      if (error) throw error;
      addToast('success', `Result forced: ${parsedNum} (${bigSmall}) for ${sessionType}`);

