import React, { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { useAuthStore } from '../store/authStore';
import { useGameStore } from '../store/gameStore';
import { 
  LayoutDashboard, Users, Activity, History, CreditCard, Settings, LogOut, CheckCircle, XCircle, Wallet
} from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

export default function AdminPanel() {
  const { user, profile, signOut, refreshProfile } = useAuthStore();
  const { addToast } = useGameStore();
  const [activeTab, setActiveTab] = useState('dashboard');
  const [renderError, setRenderError] = useState<string | null>(null);
  const [appSettings, setAppSettings] = useState({ upi_id: '' });

  // Catch initialization errors
  if (renderError) {
    return (
      <div className="min-h-screen bg-red-950 flex items-center justify-center p-4 text-white">
        <div className="bg-red-900/20 border border-red-500 p-8 rounded-2xl max-w-lg w-full">
          <h1 className="text-xl font-bold mb-4">Admin Panel Crash Detected</h1>
          <pre className="bg-black/50 p-4 rounded-lg text-xs font-mono overflow-auto mb-4">{renderError}</pre>
          <button onClick={() => window.location.reload()} className="w-full bg-red-600 py-2 rounded-lg font-bold">RELOAD SYSTEM</button>
        </div>
      </div>
    );
  }

  const [stats, setStats] = useState({
    totalUsers: 0,
    activeRounds: 5,
    totalBetsToday: 0,
    houseProfit: 0,
    totalRevenue: 0,
  });

  const [users, setUsers] = useState<any[]>([]);
  const [transactions, setTransactions] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (profile?.is_admin) {
      fetchDashboardData();
    }
  }, [profile]);

  const fetchDashboardData = async () => {
    setLoading(true);
    try {
      // Fetch user count
      const { count: userCount } = await supabase.from('profiles').select('*', { count: 'exact', head: true });

      // Fetch transactions for revenue/profit
      const { data: txs } = await supabase.from('transactions').select('*').gte('created_at', new Date(Date.now() - 86400000).toISOString());

      let profit = 0;
      let revenue = 0;

      if (txs) {
        txs.forEach(tx => {
          if (tx.type === 'loss') profit += Number(tx.amount); // User loss is house profit
          if (tx.type === 'win') profit -= Number(tx.amount); // User win is house loss
          if (tx.type === 'deposit') revenue += Number(tx.amount);
        });
      }

      setStats({
        totalUsers: userCount || 0,
        activeRounds: 5,
        totalBetsToday: txs?.filter(t => t.type === 'bet').length || 0,
        houseProfit: profit,
        totalRevenue: revenue,
      });

      const { data: userData } = await supabase.from('profiles').select('*').order('created_at', { ascending: false }).limit(50);
      if (userData) setUsers(userData);

      const { data: txData } = await supabase.from('transactions').select('*').order('created_at', { ascending: false }).limit(50);
      if (txData) setTransactions(txData);

    } catch (error) {
      console.error('Error fetching admin data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleProcessWithdrawal = async (txId: string, approve: boolean) => {
    try {
      const { data, error } = await supabase.rpc('admin_process_withdrawal', {
        p_transaction_id: txId,
        p_approve: approve
      });
      if (error) throw error;
      addToast('success', `Withdrawal ${approve ? 'approved' : 'rejected'}`);
      fetchDashboardData();
    } catch (err: any) {
      addToast('error', err.message);
    }
  };

  const handleEditBalance = async (userId: string, currentBalance: number) => {
    const newBal = prompt('Enter new balance:', currentBalance.toString());
    if (!newBal) return;

    try {
      const { error } = await supabase.rpc('admin_edit_balance', {
        p_target_user_id: userId,
        p_new_balance: Number(newBal),
        p_reason: 'Admin Adjustment'
      });
      if (error) throw error;
      addToast('success', 'Balance updated');
      fetchDashboardData();
    } catch (err: any) {
      addToast('error', err.message);
    }
  };

  const handleForceResult = async (sessionType: string) => {
    const num = prompt(`Force result for ${sessionType}\nEnter number (0-9):`);
    if (num === null) return;

    const parsedNum = parseInt(num);
    if (isNaN(parsedNum) || parsedNum < 0 || parsedNum > 9) {
      addToast('error', 'Invalid number');
      return;
    }

    const color = (parsedNum === 0 || parsedNum === 5) ? (parsedNum === 0 ? 'red-violet' : 'green-violet') : ([1,3,7,9].includes(parsedNum) ? 'green' : 'red');

    // Manual choice for Big/Small
    const bsChoice = prompt(`Calculated Size: ${parsedNum >= 5 ? 'Big' : 'Small'}\nEnter 'B' for Big or 'S' for Small (Leave empty to use calculated):`);
    let bigSmall = parsedNum >= 5 ? 'Big' : 'Small';

    if (bsChoice?.toUpperCase() === 'B') bigSmall = 'Big';
    if (bsChoice?.toUpperCase() === 'S') bigSmall = 'Small';

    const currentPeriod = useGameStore.getState().sessions[sessionType as any].period;

    try {
      const { error } = await supabase.rpc('admin_force_result', {
        p_session_type: sessionType,
        p_period: currentPeriod,
        p_number: parsedNum,
        p_color: color,
        p_big_small: bigSmall
      });
      if (error) throw error;
      addToast('success', `Result forced: ${parsedNum} (${bigSmall}) for ${sessionType}`);
    } catch (err: any) {
      addToast('error', err.message);
    }
  };

  const chartData = [
    { name: 'Mon', profit: 4000 },
    { name: 'Tue', profit: 3000 },
    { name: 'Wed', profit: 5000 },
    { name: 'Thu', profit: 2780 },
    { name: 'Fri', profit: 8890 },
    { name: 'Sat', profit: 6390 },
    { name: 'Sun', profit: stats.houseProfit },
  ];

  // --- RENDERING LOGIC ---

  if (!profile) {
    return (
      <div className="min-h-screen bg-gray-950 flex flex-col items-center justify-center text-white p-4">
        <div className="animate-spin rounded-full h-16 w-16 border-t-4 border-b-4 border-red-600 mb-6"></div>
        <h2 className="text-xl font-black italic tracking-widest text-red-600">VERIFYING ADMIN...</h2>
        <p className="text-gray-500 text-xs mt-2 font-mono">Checking credentials with secure vault</p>
      </div>
    );
  }

  if (!profile.is_admin) {
    return (
      <div className="min-h-screen bg-gray-950 flex items-center justify-center p-4">
        <div className="bg-gray-900 border border-red-900/50 p-10 rounded-[2rem] text-center max-w-sm w-full shadow-2xl">
          <XCircle className="w-20 h-20 text-red-600 mx-auto mb-6 drop-shadow-[0_0_15px_rgba(220,38,38,0.5)]" />
          <h1 className="text-3xl font-black text-white mb-2 italic">ACCESS DENIED</h1>
          <p className="text-gray-400 text-sm mb-8 leading-relaxed">
            Your current account does not have administrative privileges. 
          </p>
          <button 
            onClick={() => window.location.href = '/'}
            className="w-full bg-red-600 hover:bg-red-500 text-white font-bold py-4 rounded-2xl transition-all shadow-lg active:scale-95"
          >
            RETURN TO GAME
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 flex text-gray-900 font-sans">
      {/* Sidebar */}
      <div className="w-64 bg-gray-900 text-white flex flex-col fixed h-full shadow-2xl z-20">
        <div className="p-6 flex items-center gap-3 border-b border-gray-800">
          <div className="bg-red-600 text-white font-black text-xl w-10 h-10 flex items-center justify-center rounded-xl shadow-lg shadow-red-500/20">66</div>
          <span className="font-bold text-xl tracking-tight uppercase italic">Admin Panel</span>
        </div>

        <nav className="flex-1 py-6 px-4 space-y-2">
          {[
            { id: 'dashboard', icon: LayoutDashboard, label: 'Dashboard' },
            { id: 'monitor', icon: Activity, label: 'Games Monitor' },
            { id: 'users', icon: Users, label: 'User Control' },
            { id: 'transactions', icon: CreditCard, label: 'Financials' },
            { id: 'settings', icon: Settings, label: 'Settings' },
          ].map((item) => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-bold transition-all ${
                activeTab === item.id 
                  ? 'bg-red-600 text-white shadow-md shadow-red-600/20 translate-x-2' 
                  : 'text-gray-400 hover:bg-gray-800 hover:text-white'
              }`}
            >
              <item.icon className="w-5 h-5" />
              {item.label}
            </button>
          ))}
        </nav>

        <div className="p-6 border-t border-gray-800">
          <div className="flex items-center gap-3 mb-4">
            <div className="w-10 h-10 rounded-full bg-red-600 border-2 border-white/20 flex items-center justify-center font-black">
              {profile.username.charAt(0).toUpperCase()}
            </div>
            <div className="overflow-hidden">
              <p className="text-sm font-bold text-white leading-tight truncate">{profile.username}</p>
              <p className="text-[10px] text-red-500 font-bold uppercase tracking-tighter">Super Admin</p>
            </div>
          </div>
          <button onClick={() => { signOut(); window.location.href = '/'; }} className="w-full flex items-center justify-center gap-2 text-xs font-bold text-white bg-red-600/10 border border-red-600/20 hover:bg-red-600 transition-all py-3 rounded-xl uppercase">
            <LogOut className="w-4 h-4" />
            Logout
          </button>
        </div>
      </div>

      {/* Main Content */}
      <div className="ml-64 flex-1 flex flex-col min-h-screen">
        <header className="bg-white h-20 border-b border-gray-200 flex items-center justify-between px-8 sticky top-0 z-10">
          <h1 className="text-2xl font-black text-gray-800 capitalize tracking-tight italic">{activeTab.replace('-', ' ')}</h1>
          <div className="flex items-center gap-4">
            <span className="bg-green-100 text-green-700 text-[10px] font-black uppercase px-3 py-1.5 rounded-full flex items-center gap-1.5 border border-green-200">
              <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
              Live Control Active
            </span>
          </div>
        </header>

        <main className="p-8 flex-1 overflow-y-auto">
          {loading ? (
            <div className="flex flex-col items-center justify-center h-64 text-gray-400 gap-4">
              <div className="animate-spin rounded-full h-8 w-8 border-t-2 border-red-600"></div>
              <p className="font-bold uppercase text-xs tracking-widest">Syncing Global Data...</p>
            </div>
          ) : (
            <>
              {/* Dashboard Tab */}
              {activeTab === 'dashboard' && (
                <div className="space-y-6">
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                    {[
                      { label: 'Total Users', value: stats.totalUsers, icon: Users, color: 'text-blue-600', bg: 'bg-blue-50' },
                      { label: 'Today\'s Bets', value: stats.totalBetsToday, icon: Activity, color: 'text-orange-600', bg: 'bg-orange-50' },
                      { label: 'House Profit', value: `₹${stats.houseProfit.toLocaleString()}`, icon: CreditCard, color: 'text-red-600', bg: 'bg-red-50' },
                      { label: 'Total Revenue', value: `₹${stats.totalRevenue.toLocaleString()}`, icon: History, color: 'text-purple-600', bg: 'bg-purple-50' },
                    ].map((stat, i) => (
                      <div key={i} className="bg-white rounded-3xl p-6 shadow-sm border border-gray-100 flex items-center gap-4 transition-transform hover:scale-[1.02]">
                        <div className={`w-14 h-14 rounded-2xl flex items-center justify-center ${stat.bg} ${stat.color} shadow-sm`}>
                          <stat.icon className="w-7 h-7" />
                        </div>
                        <div>
                          <p className="text-gray-400 text-xs font-bold uppercase tracking-wider">{stat.label}</p>
                          <p className="text-2xl font-black text-gray-900">{stat.value}</p>
                        </div>
                      </div>
                    ))}
                  </div>

                  <div className="bg-white rounded-3xl shadow-sm border border-gray-100 p-8 h-96">
                    <h2 className="text-lg font-black text-gray-800 mb-6 uppercase tracking-tight">House Performance</h2>
                    <ResponsiveContainer width="100%" height="100%">
                      <LineChart data={chartData}>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#F3F4F6" />
                        <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#9CA3AF', fontSize: 12, fontWeight: 'bold'}} dy={10} />
                        <YAxis axisLine={false} tickLine={false} tick={{fill: '#9CA3AF', fontSize: 12, fontWeight: 'bold'}} dx={-10} />
                        <Tooltip 
                          contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0, 0, 0, 0.1)', padding: '12px' }}
                          cursor={{stroke: '#F3F4F6', strokeWidth: 2}}
                        />
                        <Line type="monotone" dataKey="profit" stroke="#DC2626" strokeWidth={5} dot={{r: 6, fill: '#DC2626', strokeWidth: 3, stroke: '#fff'}} activeDot={{r: 10, strokeWidth: 0}} />
                      </LineChart>
                    </ResponsiveContainer>
                  </div>
                </div>
              )}

              {/* Monitor Tab */}
              {activeTab === 'monitor' && (
                <div className="space-y-6">
                  <div className="grid grid-cols-1 gap-4">
                    {['30s', '1min', '3min', '5min', '10min'].map(sessionType => (
                      <div key={sessionType} className="bg-white border border-gray-100 rounded-[2rem] p-6 flex items-center justify-between shadow-sm hover:border-red-200 transition-all">
                        <div className="flex items-center gap-8">
                          <div className="bg-gray-900 text-white px-6 py-3 rounded-2xl font-black text-xl italic skew-x-[-10deg] shadow-lg shadow-red-600/10">
                            {sessionType.toUpperCase()}
                          </div>
                          <div className="space-y-1">
                            <div className="flex items-center gap-2">
                              <span className="w-2 h-2 rounded-full bg-green-500 animate-ping"></span>
                              <span className="text-[10px] font-black text-green-600 uppercase tracking-widest">Broadcasting Live</span>
                            </div>
                            <p className="text-xs font-bold text-gray-400 uppercase tracking-tighter">Pool Stats: <span className="text-gray-900">₹0.00 (0 Bets)</span></p>
                          </div>
                        </div>
                        <div className="flex items-center gap-3">
                          <button 
                            onClick={() => handleForceResult(sessionType)}
                            className="px-6 py-3 bg-red-600 text-white font-black rounded-xl text-xs uppercase hover:bg-red-500 transition-all shadow-md active:scale-95"
                          >
                            Force Next Result
                          </button>
                          <button className="px-6 py-3 bg-gray-100 text-gray-400 font-bold rounded-xl text-xs uppercase hover:bg-gray-200 transition-colors">
                            Pause
                          </button>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {/* Users Tab */}
              {activeTab === 'users' && (
                <div className="bg-white rounded-[2rem] shadow-sm border border-gray-100 overflow-hidden">
                  <div className="p-8 border-b border-gray-50 flex justify-between items-center">
                    <h2 className="text-xl font-black text-gray-800 uppercase italic">User Database</h2>
                    <input 
                      type="text" 
                      placeholder="Search users..." 
                      className="px-6 py-3 bg-gray-50 border border-gray-100 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-red-500 w-80 font-medium"
                    />
                  </div>
                  <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm text-gray-600">
                      <thead className="bg-gray-50/50 text-gray-400 font-black uppercase tracking-[0.2em] text-[10px] border-b border-gray-100">
                        <tr>
                          <th className="p-6 pl-8">Player</th>
                          <th className="p-6">Wallet Balance</th>
                          <th className="p-6">Rank</th>
                          <th className="p-6">Registration</th>
                          <th className="p-6 text-right pr-8">Management</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-gray-50">
                        {users.map(u => (
                          <tr key={u.id} className="hover:bg-red-50/30 transition-colors group">
                            <td className="p-6 pl-8">
                              <div className="flex items-center gap-4">
                                <div className="w-10 h-10 rounded-xl bg-gray-100 text-gray-400 group-hover:bg-red-600 group-hover:text-white flex items-center justify-center font-black transition-all">
                                  {u.username.charAt(0).toUpperCase()}
                                </div>
                                <div>
                                  <p className="font-black text-gray-900 uppercase italic tracking-tight">{u.username}</p>
                                  <p className="text-[10px] text-gray-400 font-mono tracking-tighter uppercase">{u.id.substring(0, 12)}</p>
                                </div>
                              </div>
                            </td>
                            <td className="p-6">
                              <span className="font-black text-gray-900 text-lg">₹{Number(u.balance).toLocaleString()}</span>
                            </td>
                            <td className="p-6">
                              <span className={`px-3 py-1 rounded-lg text-[9px] font-black uppercase tracking-widest ${u.is_admin ? 'bg-red-600 text-white shadow-lg shadow-red-600/20' : 'bg-gray-100 text-gray-500'}`}>
                                {u.is_admin ? 'Admin' : 'Player'}
                              </span>
                            </td>
                            <td className="p-6 text-gray-400 font-bold uppercase text-[10px]">{new Date(u.created_at).toLocaleDateString()}</td>
                            <td className="p-6 text-right pr-8">
                              <button onClick={() => handleEditBalance(u.id, u.balance)} className="text-red-600 hover:text-red-700 font-black text-[10px] uppercase tracking-widest bg-red-50 px-4 py-2 rounded-xl transition-all active:scale-95">Edit Wallet</button>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              )}

              {/* Transactions Tab */}
              {activeTab === 'transactions' && (
                <div className="bg-white rounded-[2rem] shadow-sm border border-gray-100 overflow-hidden">
                  <div className="p-8 border-b border-gray-50 flex justify-between items-center">
                    <h2 className="text-xl font-black text-gray-800 uppercase italic">Financial Stream</h2>
                  </div>
                  <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm text-gray-600">
                      <thead className="bg-gray-50/50 text-gray-400 font-black uppercase tracking-[0.2em] text-[10px] border-b border-gray-100">
                        <tr>
                          <th className="p-6 pl-8">Timestamp</th>
                          <th className="p-6">Account</th>
                          <th className="p-6">Flow</th>
                          <th className="p-6">Value</th>
                          <th className="p-6">Audit Status</th>
                          <th className="p-6 text-right pr-8">Operation</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-gray-50">
                        {transactions.map(tx => (
                          <tr key={tx.id} className="hover:bg-gray-50/50 transition-colors">
                            <td className="p-6 pl-8 text-gray-400 font-bold text-[10px] uppercase">{new Date(tx.created_at).toLocaleString()}</td>
                            <td className="p-6 font-mono text-[10px] text-gray-400 uppercase">{tx.user_id.substring(0, 12)}</td>
                            <td className="p-6">
                              <span className="capitalize font-black text-gray-900 italic">{tx.type}</span>
                            </td>
                            <td className="p-6 font-black text-gray-900">₹{Number(tx.amount).toLocaleString()}</td>
                            <td className="p-6">
                              <span className={`flex items-center gap-2 font-black uppercase text-[10px] tracking-tighter ${tx.status === 'completed' ? 'text-green-600' : tx.status === 'pending' ? 'text-orange-500' : 'text-red-600'}`}>
                                {tx.status === 'completed' ? <CheckCircle className="w-4 h-4"/> : tx.status === 'pending' ? <Activity className="w-4 h-4 animate-pulse"/> : <XCircle className="w-4 h-4"/>}
                                {tx.status}
                              </span>
                            </td>
                            <td className="p-6 text-right pr-8">
                              {tx.status === 'pending' && tx.type === 'withdrawal' && (
                                <div className="flex justify-end gap-2">
                                  <button onClick={() => handleProcessWithdrawal(tx.id, true)} className="bg-green-600 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase shadow-lg shadow-green-600/20 active:scale-95 transition-all">Approve</button>
                                  <button onClick={() => handleProcessWithdrawal(tx.id, false)} className="bg-red-600 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase shadow-lg shadow-red-600/20 active:scale-95 transition-all">Reject</button>
                                </div>
                              )}
                              {tx.status !== 'pending' && <span className="text-gray-200 font-black">—</span>}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              )}

              {/* Settings placeholder */}
              {activeTab === 'settings' && (
                <div className="bg-white rounded-[2rem] shadow-sm border border-gray-100 p-20 text-center">
                  <div className="w-24 h-24 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-6">
                    <Settings className="w-12 h-12 text-gray-300 animate-[spin_10s_linear_infinite]" />
                  </div>
                  <h2 className="text-2xl font-black text-gray-800 mb-2 italic uppercase">System Core</h2>
                  <p className="text-gray-400 font-bold text-xs uppercase tracking-widest">Administrative console under encryption</p>
                </div>
              )}
            </>
          )}
        </main>
      </div>
    </div>
  );
}

